  'changzhou/pagoda': ('معبد تياننينغ', 'يرتفع هذا المعبد في وسط المدينة ليصل طوله إلى 153 متراً، مما يجعله أطول معبد في العالم.'),
  'changzhou/comb': ('حرفة الأمشاط', 'كانت أمشاط تشانغتشو المصنوعة يدوياً منذ آلاف السنين تُقدم كهدايا للقصور الإمبراطورية.'),
  'changzhou/canal': ('القناة الكبرى', 'يستمتع الزوار بالتنزه على ضفاف القناة لاستكشاف أحيائها القديمة ومشاهدة أضوائها الليلية.'),
  'shaoxing/wine': ('نبيذ شاوشينغ', 'يُصنع هنا نبيذ الأرز الأصفر الشهير المستخدم في المطبخ الصيني منذ آلاف السنين.'),
  'shaoxing/bridge': ('الجسور الحجرية', 'تحتفظ مدينة شاوشينغ، التي تتخللها القنوات المائية، بمئات الجسور الحجرية المقوسة.'),
  'shaoxing/pen': ('مهد الخط العربي الصيني', 'يُعد جناح الأوركيد الخاص بالخطاط الشهير وانغ شي تشي موقعاً مقدساً لفن الخط.'),
  'shaoxing/boat': ('قوارب ووبنغ', 'تُعد قوارب ووبنغ ذات المظلات السوداء، التي تُجدف بالأقدام، وسيلة التنقل الكلاسيكية في القنوات المائية.'),
  'bengbu/shell': ('ميناء اللؤلؤ', 'يعني اسم المدينة \'رصيف المحار\'، وقد اشتهرت قديماً بإنتاج لآلئ نهر هواي.'),
  'bengbu/train': ('بوابة السكك الحديدية', 'تعد مدينة بنغبو نقطة عبور رئيسية لنهر هواي، وقد ازدهرت المدينة بفضل محطة قطاراتها التي تربط الشمال بالجنوب.'),
  'bengbu/river': ('نهر هواي', 'يجري هذا النهر عبر المدينة، ويُعرف تاريخياً بكونه الخط الفاصل بين شمال الصين وجنوبها.'),
  'bengbu/blossom': ('مهرجانات الربيع', 'تكتسي الحدائق المطلة على ضفاف النهر بحلة زاهية خلال مهرجانات الزهور التي تقام كل ربيع.'),
  'jiujiang/mountain': ('جبل لو', 'ألهمت قمم جبل لو الضبابية، المدرج ضمن قائمة اليونسكو للتراث العالمي، العديد من الشعراء والرسامين عبر العصور.'),
  'jiujiang/tea': ('شاي السحاب والضباب', 'يُعد شاي "يون وو" المستخلص من منحدرات جبل لو من بين أرقى وأجود أنواع الشاي في الصين.'),
  'jiujiang/lake': ('بحيرة بويانغ', 'تُعد بحيرة بويانغ أكبر بحيرة للمياه العذبة في الصين، وتستقبل آلاف طيور الكركي المهاجرة في فصل الشتاء.'),
  'jiujiang/scroll': ('مدينة القصائد', 'خُطت أبيات الشعراء العظام مثل باي جويي وسو شي على بوابات هذه المدينة المطلة على النهر.'),
  'quanzhou/ship': ('طريق الحرير البحري', 'كانت مدينة تشوانتشو، التي عرفها ماركو بولو باسم "زيتون"، أعظم ميناء في العالم خلال العصور الوسطى وهي مدرجة ضمن قائمة اليونسكو.'),
  'quanzhou/mosque': ('مسجد تشينغجينغ', 'يُعد هذا المسجد الحجري الذي شُيد عام 1009 ميلادي من بين أقدم المساجد في الصين.'),
  'quanzhou/puppet': ('فن العرائس', 'يُعتبر فن تحريك العرائس بالخيوط في تشوانتشو تقليداً مسرحياً عريقاً يعود تاريخه إلى ألف عام.'),
  'quanzhou/tea': ('شاي تيغوانين', 'يُعرف شاي الأولونغ القادم من منطقة أنشي المجاورة عالمياً باسم شاي "الإلهة الحديدية".'),
  'shanghai/pearl': ('برج لؤلؤة الشرق', 'يُعتبر هذا البرج، بكراته الوردية التي تعلو نهر هوانغبو، الأيقونة المعمارية لمدينة شنغهاي الحديثة.'),
  'shanghai/bund': ('منطقة البوند', 'تعكس واجهات الفنادق والمباني التاريخية على ضفاف النهر عظمة شنغهاي في الماضي.'),
  'shanghai/garden': ('حديقة يو', 'تُعد هذه الحديقة الكلاسيكية التي تعود إلى عهد أسرة مينغ واحة من الهدوء في قلب المدينة بفضل صخورها وبركها المائية.'),
  'shanghai/xlb': ('زلابية الحساء', 'تُعتبر هذه الفطائر المطهوة على البخار والمحشوة بالمرق الساخن تحفة فنية في وجبة إفطار شنغهاي.'),
  'hangzhou/lake': ('البحيرة الغربية', 'تُعد هذه البحيرة، بما تضمه من أشجار الصفصاف والجزر والجسور المقوسة، أكثر البحيرات التي تغنى بها الشعراء الصينيون.'),
  'hangzhou/tea': ('شاي لونغجينغ', 'يُزرع شاي "بئر التنين" الأخضر على المنحدرات المحيطة بالبحيرة، ويُعتبر أشهر أنواع الشاي في الصين.'),
  'hangzhou/temple': ('معبد لينغين', 'يشتهر هذا المعبد الذي يعود تاريخه إلى 1700 عام، والمعروف بـ "معبد ملاذ الروح"، بمنحوتاته الصخرية وتمثال بوذا العملاق.'),
  'hangzhou/silk': ('مدينة الحرير', 'يُنسج حرير هانغتشو منذ ألف عام، وهو الذي شكل ثروة الطرف الشرقي لطريق الحرير التاريخي.'),
  'chongqing/hongya': ('كهف هونغيا', 'مجمع من المنازل المبنية على ركائز متينة فوق المنحدر الصخري، يتلألأ ليلاً فوق النهر كأنه مشهد من القصص الخيالية.'),
  'chongqing/hotpot': ('قدر تشونغتشينغ الساخن', 'يُعد هذا الطبق، الذي يغلي بالزيت الحار والفلفل المخدر، الروح النارية لمدينة الجبال.'),
  'chongqing/monorail': ('قطار تشونغتشينغ المعلق', 'يُعتبر القطار الخفيف الذي يخترق المباني السكنية المشهد الأيقوني لهذه المدينة المبنية على التلال.'),
  'chongqing/river': ('مضايق نهر اليانغتسي', 'تنطلق رحلات السفن السياحية عبر المضايق الثلاثة من هذا الميناء، حيث ترتفع المدينة عند ملتقى نهرين عظيمين.'),
  'dalian/square': ('ساحة شينغهاي', 'تُعد أكبر ساحة مدينة في آسيا، وتنبض بالحياة خلال المهرجانات والعروض الفنية على طول الواجهة البحرية.'),
  'dalian/beach': ('شواطئ داليان', 'بفضل خلجانها الصخرية وصيفها المعتدل، تُعد داليان الوجهة الساحلية المفضلة في شمال الصين.'),
  'dalian/football': ('مدينة كرة القدم', 'تُلقب بـ "مهد كرة القدم" في الصين، حيث نشأت فيها أكثر الأندية تتويجاً بالألقاب في البلاد.'),
  'dalian/seafood': ('مأكولات داليان البحرية', 'تتزين موائد المدينة بأشهى المأكولات البحرية من مياه البحر الأصفر الباردة، مثل الإسكالوب والروبيان وقنفذ البحر.'),
  'shenyang/palace': ('قصر موكدين', 'هو القصر الأول لسلالة تشينغ، ويُعتبر بمثابة الشقيق الأصغر للمدينة المحرمة في بكين.'),
  'shenyang/tomb': ('مقابر تشينغ', 'تُعد المقابر الشرقية والشمالية التي تحيط بالمدينة أضرحة أثرية لمؤسسي سلالة تشينغ.'),
  'shenyang/factory': ('مهد الصناعة', 'وُلدت الصناعات الثقيلة الصينية هنا، وقد أكسبتها مصانعها الضخمة لقب "رور الشرق".'),
  'shenyang/dumpling': ('زلابية لاوبيان', 'تُعد زلابية لاوبيان المطهوة على البخار، والتي يعود تاريخها إلى مئتي عام، الطبق الأشهر على المائدة الشمالية.'),
  'hefei/judge': ('ضريح القاضي باو', 'يُعتبر القاضي العادل باو تشنغ، المولود في هذه المدينة، رمزاً للعدالة، ويُعد ضريحه معبداً للنزاهة.'),
  'hefei/science': ('مدينة العلوم', 'مركز تقني متطور يضم نخبة من الجامعات والمختبرات الرائدة في الصين.'),
  'hefei/lake': ('بحيرة تشاوهو', 'واحدة من أكبر خمس بحيرات للمياه العذبة في الصين، وتشتهر بأسماكها البيضاء وسرطان البحر.'),
  'hefei/cake': ('كعكة السمسم لو', 'تُعد كعكة السمسم المحشوة بالحلوى من أقدم المأكولات التقليدية في مدينة لوتشو العريقة.'),
  'foshan/wingchun': ('وينغ تشون', 'تُعد المدينة موطن فن الوينغ تشون القتالي، حيث تعود إليها جذور المعلم ييب مان وبروس لي.'),
  'foshan/lion': ('رقصة الأسد', 'تُعتبر المدينة عاصمة رقصة الأسد الجنوبية، حيث تقفز الأسود الملونة ببراعة فوق الأعمدة خلال المهرجانات.'),
  'foshan/ceramic': ('فخار شيوان', 'لا تزال أفران الفخار التي يعود تاريخها إلى ألف عام تنتج تماثيل شيوان الحيوية.'),
  'foshan/opera': ('أوبرا كانتونية', 'تطورت أوبرا كانتون، وهي فن المسرح الأكثر شعبية في جنوب الصين، على هذه الأراضي.'),
  'guiyang/pavilion': ('جناح جياشيو', 'يُعد هذا الجناح المكون من ثلاث طبقات والمطل على نهر نانمينغ رمزاً للمدينة منذ أربعمئة عام.'),
  'guiyang/sourfish': ('سمك بالحساء الحامض', 'يُعد السمك المطهو في مرق الطماطم المخمرة الحامضة الطبق المميز لمقاطعة قويتشو.'),
  'guiyang/waterfall': ('شلالات هوانغغوشو', 'تتدفق واحدة من أكبر شلالات آسيا بقوة، مما يخلق أقواس قزح مذهلة في الأفق.'),
  'guiyang/miao': ('ثقافة مياو', 'تضفي مهرجانات شعب المياو المتوجين بالفضة وفنون تطريزهم البهجة على القرى الجبلية.'),
  'changchun/film': ('مدينة السينما', 'تضم المدينة الاستوديوهات التي ولدت فيها السينما الصينية، وتُعرف بلقب هوليوود الشرق.'),
  'changchun/car': ('مدينة السيارات', 'خرجت أول سيارة صينية الصنع من مصانع هذه المدينة، التي تُعد العاصمة الوطنية لصناعة السيارات.'),
  'changchun/palace': ('قصر الإمبراطور الأخير', 'يعد هذا القصر الذي عاش فيه آخر أباطرة الصين شاهداً صامتاً على حقبة تاريخية مضطربة.'),
  'changchun/snow': ('ثلوج الشتاء', 'تتألق المدينة خلال فصل الشتاء الطويل بمنحوتات جليدية ومسارات للتزلج وسط الثلوج البيضاء.'),
  'xining/lake': ('بحيرة تشينغهاي', 'تُعرف أكبر بحيرة مالحة في الصين بحقول زهور اللفت الصفراء التي تحيط بها في فصل الصيف.'),
  'xining/monastery': ('دير كومبوم', 'يُعد أحد الأديرة الستة الكبرى للبوذية التبتية، ويشتهر بمنحوتاته المصنوعة من زبدة الياك.'),
  'xining/flower': ('زهور اللفت', 'تكتسي الهضبة في شهر يوليو بحقول ذهبية من زهور اللفت تمتد حتى الأفق.'),
  'xining/lamb': ('لحم الياك والضأن', 'تتميز نكهات الهضبة بأطباق المعكرونة المسحوبة يدوياً وأسياخ لحم الضأن التي تشتهر بها مطابخ قوميتي هوي والتبت.'),
  'guilin/karst': ('تضاريس كارست في نهر لي', 'تعد القمم الكلسية التي ترتفع وسط الضباب المشهد المطبوع على ورقة العشرين يوان النقدية.'),
  'guilin/elephant': ('تلة جذع الفيل', 'تعتبر الصخرة التي تتخذ شكل فيل يغمس خرطومه في النهر الرمز المحبوب للمدينة.'),
  'guilin/terrace': ('مصاطب لونغجي للأرز', 'تُشكل مصاطب "عمود التنين" التي تلتف حول المنحدرات سلماً يعكس قروناً من الكد والعمل.'),
  'guilin/osmanthus': ('أزهار الأوسمانثوس', 'يعني اسم المدينة "غابة الأوسمانثوس"، حيث تغرق في عطر أزهارها الحلو في فصل الخريف.'),
  'wenzhou/merchant': ('روح التجارة', 'يُعرف رواد الأعمال في ونتشو ببراعتهم التجارية، حيث أسسوا شبكات أعمال تمتد في جميع أنحاء العالم.'),
  'wenzhou/shoe': ('الأحذية والجلود', 'تنتج هذه المدينة الصناعية حصة ضخمة من الأحذية الجلدية التي تُباع في الأسواق العالمية.'),
  'wenzhou/mountain': ('جبال ياندانغ', 'تُعرف هذه الجبال بشلالاتها وقممها المسننة، وتُلقب بـ "الجبل الأول المطل على البحر".'),
  'wenzhou/seafood': ('المأكولات البحرية', 'تعتمد المائدة المحلية في ونتشو بشكل أساسي على الحبار والمحار والأسماك المستخرجة من بحر الصين الشرقي.'),
  'tangshan/memorial': ('نصب تذكاري لزلزال تانغشان', 'يعد هذا المتنزه التذكاري المخصص لزلزال عام 1976 الكبير رمزاً لمدينة ولدت من جديد.'),
  'tangshan/coal': ('منجم الفحم والصلب', 'تُعد هذه المدينة مهد الصناعة الصينية، حيث افتُتح فيها أول منجم فحم وسكة حديدية حديثة في البلاد.'),
  'tangshan/ceramic': ('خزف تانغشان', 'تُعرف المدينة بلقب "مدينة الخزف في الشمال"، حيث يضفي خزف العظام الفاخر الذي تنتجه لمسة من الأناقة على الموائد.'),
  'tangshan/lake': ('حديقة نانهو', 'تحولت حفرة منجم قديمة إلى حديقة بحيرة خلابة أصبحت بمثابة الرئة الخضراء للمدينة.'),
  'anshan/steel': ('مدينة الصلب', 'تأسس هنا أكبر مصنع للصلب في الصين، مما جعل المدينة تُلقب بـ "عاصمة الصلب" في البلاد.'),
  'anshan/jade': ('يشم شيويان', 'تضم المدينة أكبر منحوتة يشم في العالم، وتُعتبر بحق أرض اليشم في الصين.'),
  'anshan/mountain': ('جبل تشيان', 'يُعرف الجبل بـ "قمم اللوتس الألف"، وهو قمة مقدسة في الشمال تشتهر بمعابدها وتضاريسها الصخرية.'),
  'anshan/spring': ('ينابيع تانغقانغزي', 'ينابيع حارة يقصدها الناس منذ ألف عام للاستشفاء، وقد كانت وجهة مفضلة للأباطرة قديماً.'),
  'linyi/market': ('سوق الجملة', 'يُعد أكبر مركز لتجارة الجملة في شمال الصين، حيث تُشحن البضائع منه إلى جميع أنحاء البلاد.'),
  'linyi/brush': ('موطن الخطاطين', 'وُلد هنا وانغ شي تشي، الملقب بـ "حكيم الخط" في الصين، مما جعل المدينة تُعرف بأرض الحبر والفرشاة.'),
  'linyi/mountain': ('جبل منغ', 'يُعد ثاني أعلى جبل في مقاطعة شاندونغ، وهو بمثابة منتجع طبيعي غني بالهواء النقي والشلالات.'),
  'linyi/pancake': ('فطائر ييمينغ', 'تُعتبر فطائر الذرة الرقيقة "جيان بينغ" الغذاء الأساسي التقليدي لسكان جبال ييمينغ منذ القدم.'),
  'cangzhou/lion': ('الأسد الحديدي', 'يُعد تمثال الأسد الحديدي الضخم الذي يعود تاريخه إلى 1100 عام رمزاً للفخر في المدينة.'),
  'cangzhou/martial': ('الفنون القتالية', 'تُعرف المدينة بأنها "موطن الووشو" في الصين، حيث خرج منها أشهر الأساتذة ومدارس الفنون القتالية.'),
  'cangzhou/canal': ('القناة الكبرى', 'تمر القناة الكبرى الواصلة بين بكين وهانغتشو عبر المدينة، ولا تزال أرصفتها القديمة قائمة حتى اليوم.'),
  'cangzhou/jujube': ('العناب الذهبي', 'يُلقب العناب ذو القشرة الرقيقة والمذاق الحلو بـ "ملك الفواكه المجففة".'),
  'nantong/textile': ('مدينة المنسوجات', 'تُعد نانتونغ عاصمة المنسوجات المنزلية في الصين، حيث تصل أقمشتها القطنية إلى الأسواق في جميع أنحاء العالم.'),
  'nantong/mountain': ('جبل لانغ', 'يرتفع هذا الجبل المقدس ذو القمم الخمس عند مصب نهر يانغتسي، ويُعتبر وجهة شهيرة للحج والاستمتاع بالمناظر الطبيعية.'),
  'nantong/kite': ('الطائرة الورقية الصفارة', 'تُعد طائرات "بانيو" الورقية المزودة بصفارات تصدر طنيناً حرفة تقليدية عريقة تشتهر بها المدينة.'),
  'nantong/school': ('رائد التعليم', 'أسس الصناعي تشانغ جيان هنا أول المدارس والمتاحف الحديثة في الصين.'),
  'taizhou/opera': ('مي لان فانغ', 'تُعد هذه المدينة مسقط رأس مي لان فانغ، الأستاذ الأسطوري لأوبرا بكين.'),
  'taizhou/tea': ('شاي الصباح', 'يُعتبر طقس "زاو تشا" الصباحي، الذي يتضمن تناول الكعك المطهو على البخار مع الشاي المخمر، تقليداً أصيلاً في المدينة.'),
  'taizhou/boat': ('مهرجان قوارب تشينتونغ', 'في فصل الربيع، ينبض النهر بالحياة خلال مهرجان يضم مئات المجدفين في سباقات حماسية.'),
  'taizhou/meatball': ('كرات لحم رأس الأسد', 'تُعد كرات لحم الخنزير الكبيرة والطرية المعروفة باسم "رأس الأسد" طبقاً كلاسيكياً من مطبخ هوايانغ.'),
  'jinhua/ham': ('لحم جينهوا المقدد', 'يُعد هذا اللحم الأحمر، الذي يُعالج بطريقة تعود لقرون مضت، الأشهر من نوعه في الصين.'),
  'jinhua/film': ('استوديوهات هنغديان', 'تُعد أكبر موقع تصوير سينمائي خارجي في العالم، حيث يتم تصوير عدد لا يحصى من المسلسلات التاريخية.'),
  'jinhua/cave': ('كهف التنين المزدوج', 'يخطف هذا الكهف الجوفي الأنفاس، حيث يتم الدخول إليه بالقوارب عبر بوابة صخرية منخفضة.'),
  'jinhua/bridge': ('الجسور القديمة', 'تجسد الجسور الحجرية المقوسة والبلدات المائية سحر منطقة جيانغنان وجمالها.'),
  'wuhu/park': ('فانغتي وندرلاند', 'تُعد واحدة من أكبر مدن الملاهي في الصين، وتوفر للعائلات أياماً مليئة بالإثارة والمرح.'),
  'wuhu/ironart': ('الرسم بالحديد', 'تُعد لوحات "الرسم بالحديد" الأنيقة، التي تُصاغ من الحديد المطاوع، حرفة يدوية يعود تاريخها إلى 300 عام.'),
  'wuhu/rice': ('ميناء الأرز', 'كانت هذه المدينة الواقعة على ضفاف نهر يانغتسي تاريخياً أكبر سوق للأرز في الصين.'),
  'wuhu/river': ('ميناء يانغتسي', 'يُعد هذا الميناء النهري النشط البوابة الرئيسية لمدينة ووهو ومقاطعة آنهوي نحو البحر.'),
  'huangshan/peak': ('الجبل الأصفر', 'يُعتبر الجبل الأشهر في الصين بفضل قمم الجرانيت وبحر السحب وأشجار الصنوبر الملتوية.'),
  'huangshan/village': ('قرية هونغ تسون', 'تُصنف هذه القرية ذات الجدران البيضاء والمجاري المائية ضمن قائمة اليونسكو للتراث العالمي، وتبدو وكأنها لوحة فنية.'),
  'huangshan/tea': ('شاي ماوفنغ', 'يُقطف هذا الشاي الأخضر ذو البراعم الزغبية من المنحدرات الضبابية، ويُصنف ضمن أنواع الشاي العشرة الأكثر شهرة في الصين.'),
  'huangshan/ink': ('حبر وفنون هويتشو', 'يُعد حبر هوي والمنازل الخشبية المنحوتة وفن الخط من الكنوز الثقافية لهذه المنطقة.'),
  'yichun/moon': ('جبل مينغيويه', 'يشتهر جبل \'القمر المضيء\' بينابيعه الحارة وإطلالاته البانورامية عبر التلفريك.'),
  'yichun/spring': ('الينابيع الحارة', 'جعلت الينابيع الحارة النادرة والغنية بالسيلينيوم من المدينة مركزاً للاستشفاء في الصين.'),
  'yichun/zen': ('بوذية تشان', 'تدعو المعابد الجبلية المتجذرة في طوائف \'تشان\' الصينية الزوار إلى التأمل والسكينة.'),
  'yichun/rice': ('سهل الأرز', 'لطالما كان سهل يوان-هي الخصيب بمثابة سلة الغذاء لمقاطعة جيانغشي.'),
  'zhangzhou/narcissus': ('زهرة النرجس', 'تنمو هنا أشهر أبصال النرجس في الصين، والتي تُعد رمزاً لاحتفالات الربيع.'),
  'zhangzhou/tulou': ('بيوت التولو (بيوت الهاكا الطينية)', 'تُعد هذه القلاع الدائرية الضخمة المصنوعة من التربة المدكوكة موقعاً تراثياً لليونسكو، وتجمع القرية بأكملها تحت سقف واحد.'),
  'zhangzhou/banana': ('الفواكه الاستوائية', 'تُحافظ بساتين الموز واللونغان واليوسفي على اخضرار الدلتا الدافئة طوال العام.'),
  'zhangzhou/coast': ('جزيرة دونغشان', 'تُعتبر الجزيرة جوهرة الساحل الجنوبي بفضل شواطئها الذهبية وقراها التي يعمل سكانها في صيد الأسماك.'),
  'guangzhou/tower': ('برج كانتون', 'يُعرف ببرج \'الخصر النحيل\'، وهو أحد أطول الأبراج في العالم، ويتوج المدينة بألوانه المتغيرة ليلاً.'),
  'guangzhou/dimsum': ('شاي الصباح (يام تشا)', 'يُعد \'يام تشا\' - وهو عبارة عن وجبات ديم سام المطهوة بالبخار في سلال الخيزران مع الشاي - روح المطبخ الكانتوني.'),
  'guangzhou/academy': ('أكاديمية عشيرة تشن', 'تُعد قاعة العشيرة هذه تحفة فنية من الحرف الكانتونية، وتشتهر بمنحوتاتها الخشبية وزخارفها الخزفية البديعة.'),
  'guangzhou/flower': ('مدينة الزهور', 'تُلقب غوانزو بـ "مدينة الزهور" نظراً لأزهارها التي تتفتح طوال العام، وإقامة معارض الزهور الضخمة فيها مع كل عام جديد.'),
  'wuhan/crane': ('برج الكركي الأصفر', 'يطل هذا البرج الذي يعود تاريخه إلى ألف عام على نهر يانغتسي، وقد كان مصدراً لإلهام أشهر القصائد الصينية.'),
  'wuhan/noodle': ('نودلز ساخنة وجافة', 'تُعتبر النودلز الساخنة والجافة الممزوجة بمعجون السمسم وجبة الإفطار التي لا غنى عنها في ووهان.'),
  'wuhan/duckneck': ('رقبة البط الحارة', 'تُعد رقبة البط المطهوة بالتوابل الحارة الوجبة الخفيفة المفضلة لدى سكان المدينة خلال جلسات السمر الليلية.'),
  'wuhan/university': ('أزهار الكرز في الحرم الجامعي', 'تجذب أزهار الكرز في جامعة ووهان آلاف الزوار للاستمتاع بجمالها في كل ربيع.'),
  'tianjin/eye': ('عين تيانجين', 'هي عجلة ترفيهية ضخمة بُنيت فوق جسر، وتوفر إطلالة بانورامية على ضفتي النهر في آن واحد.'),
  'tianjin/baozi': ('فطائر غوبولي', 'تُعد فطائر لحم الخنزير المطهوة على البخار ذات الطيات المميزة العلامة التجارية الشهيرة للمدينة منذ 150 عاماً.'),
  'tianjin/crosstalk': ('كوميديا شيانغشينغ', 'يُعد فن "الشيانغشينغ" الكوميدي القائم على الحوار بين شخصين تقليداً أصيلاً في تيانجين نشأ في مقاهي الشاي الخاصة بها.'),
  'tianjin/architecture': ('الحي الأوروبي', 'اكتسبت المدينة لقب "متحف العمارة" بفضل الفيلات ذات الطراز الأوروبي المنتشرة في شوارعها الخمسة الكبرى.'),
  'xiamen/island': ('جزيرة غولانغيو', 'تُعد هذه الجزيرة المدرجة ضمن قائمة اليونسكو متحفاً مفتوحاً بفضل أزقتها الخالية من السيارات وفيلاتها ذات الطراز الاستعماري.'),
  'xiamen/piano': ('جزيرة البيانو', 'تُلقب غولانغيو بـ "جزيرة البيانو" نظراً لامتلاك سكانها أكبر عدد من آلات البيانو للفرد الواحد مقارنة بأي مكان آخر.'),
  'xiamen/egret': ('البلشون الأبيض', 'يُعد البلشون الأبيض رمزاً للمدينة، وهو ما يذكرنا باسمها القديم "جزيرة البلشون".'),
  'xiamen/oyster': ('عجة المحار', 'تُعتبر عجة المحار المقرمشة والمصنوعة من المحار الطازج والبيض نجم المطبخ الساحلي في المدينة.'),
  'harbin/ice': ('مهرجان الجليد', 'يُعد مهرجان الشتاء في هاربين، الذي يضم قصوراً جليدية عملاقة مضاءة، الأكبر من نوعه في العالم.'),
  'harbin/cathedral': ('كاتدرائية القديسة صوفيا', 'تُعد هذه الكاتدرائية الأرثوذكسية الروسية ذات القباب البصلية رمزاً لماضي المدينة الأوروبي.'),
  'harbin/sausage': ('السجق الأحمر', 'يُعتبر السجق الأحمر المدخن على الطريقة الروسية من الأطباق الشهية التي تشتهر بها المدينة منذ قرن من الزمان.'),
  'harbin/accordion': ('مدينة الموسيقى', 'بفضل تراثها الروسي العريق، احتضنت مدينة هاربين أول أوركسترا سيمفونية في الصين.'),
  'fuzhou/alley': ('الأزقة الثلاثة والحارات السبع', 'يُعد هذا الحي القديم بجدرانه البيضاء وقرميده الأسود متحفاً حياً للعمارة التي تعود لعصري مينغ وتشينغ.'),
  'fuzhou/banyan': ('مدينة أشجار البانيان', 'تُلقب فوتشو بمدينة البانيان، حيث تظلل أشجار البانيان العملاقة والقديمة شوارعها.'),
  'fuzhou/hotspring': ('الينابيع الحارة', 'تتدفق الينابيع الحارة في وسط المدينة وتغذي الحمامات العامة منذ ألف عام.'),
  'fuzhou/soup': ('حساء بوذا يقفز فوق الجدار', 'يُعد هذا الحساء الفاخر، المطهو من عشرات المكونات، تحفة المطبخ في مقاطعة فوجيان.'),
  'dongguan/robot': ('مصنع العالم', 'بفضل مصانعها المؤتمتة، تنتج دونغوان حصة ضخمة من الإلكترونيات في العالم.'),
  'dongguan/basketball': ('مدينة كرة السلة', 'يقع مقر أكثر أندية كرة السلة تتويجاً في الصين داخل هذه المدينة المعروفة بمدينة كرة السلة.'),
  'dongguan/keyuan': ('حديقة كيوان', 'تُعد واحدة من الحدائق الكلاسيكية الأربع الشهيرة في غوانغدونغ، وتتميز ببركها وأجنحتها الجميلة.'),
  'dongguan/cannon': ('حصون هومين', 'تُشير حصون هومين، حيث بدأت حرب الأفيون، إلى الشاطئ الذي أُحرقت فيه شحنات الأفيون.'),
  'lanzhou/beefnoodle': ('نودلز لانشو باللحم البقري', 'بمرقها الصافي ونودلزها المسحوبة يدوياً، تُعتبر لانشو عاصمة النودلز في الصين.'),
  'lanzhou/waterwheel': ('النواعير المائية', 'ترمز النواعير المائية العملاقة على ضفاف النهر الأصفر إلى قرون من هندسة الري.'),
  'lanzhou/statue': ('تمثال الأم للنهر الأصفر', 'يجسد تمثال الأم والطفل على ضفة النهر، النهر الذي غذى الحضارة الصينية.'),
  'lanzhou/raft': ('قوارب جلود الأغنام', 'لا تزال القوارب التقليدية المصنوعة من جلود الأغنام المنفوخة تطفو فوق مياه النهر الأصفر.'),
  'urumqi/bazaar': ('البازار الكبير', 'يتميز البازار بأبراج مآذنه وأكشاك التوابل التي تعكس ألوان طريق الحرير الزاهية.'),
  'urumqi/tianshan': ('بحيرة تيانشي', 'تحيط غابات التنوب ببحيرة تيانشي التي تقع عند سفح قمم جبال تيانشان الثلجية.'),
  'urumqi/kebab': ('كباب لحم الضأن', 'تُعد أسياخ لحم الضأن المتبلة والمشوية على الفحم طبقاً أساسياً على المائدة الأويغورية.'),
  'urumqi/dance': ('الرقص الأويغوري', 'تضفي رقصات الأويغور الدوارة على أنغام الطبول وآلة الرواب البهجة على كل احتفال.'),
  'haikou/coconut': ('مدينة جوز الهند', 'تكتسي شوارع هايكو بأشجار جوز الهند، مما أكسبها لقب مدينة جوز الهند.'),
  'haikou/arcade': ('أروقة تشيلو', 'تشكل مباني تشيلو ذات الأعمدة في جنوب الصين شوارع مسقوفة ومظللة.'),
  'haikou/crater': ('الفوهات البركانية', 'تُشكل الفوهات البركانية الخامدة حديقة جيولوجية خضراء على أطراف المدينة.'),
  'haikou/turtle': ('البحر الاستوائي', 'تجعل المياه الدافئة والصافية والشعاب المرجانية من الساحل موطناً للسلاحف البحرية.'),
  'luoyang/grotto': ('كهوف لونغمن', 'تُعد كهوف لونغمن، التي تضم عشرات الآلاف من تماثيل بوذا المنحوتة في المنحدرات، كنزاً فنياً مدرجاً ضمن قائمة اليونسكو.'),
  'luoyang/peony': ('عاصمة الفاوانيا', 'تزهر آلاف أزهار الفاوانيا في شهر أبريل من كل عام، مما يجعل لويانغ عاصمة لهذه الزهرة.'),
  'luoyang/whitehorse': ('معبد الحصان الأبيض', 'تأسس هذا المعبد عام 68 ميلادي، ويُعتبر أول دير بوذي في الصين.'),
  'luoyang/capital': ('العاصمة القديمة', 'تُعد لويانغ مهد الحضارة الصينية، حيث كانت عاصمة لثلاث عشرة سلالة حاكمة.'),
  'shantou/gongfutea': ('شاي غونغفو', 'يُعد شاي غونغفو في منطقة تشاوشان فناً من فنون الضيافة، حيث يُحضر بعناية في أكواب صغيرة.'),
  'shantou/beefpot': ('قدر اللحم البقري', 'يشتهر قدر تشاوشان الساخن بطهي شرائح اللحم البقري الطازجة الرقيقة في ثوانٍ معدودة.'),
  'shantou/opera': ('أوبرا تشوتشو', 'تشتهر أوبرا تشوتشو، التي يعود تاريخها إلى 600 عام، بأغانيها الرقيقة وأزيائها المطرزة.'),
  'shantou/harbor': ('ميناء شانتو', 'يُعد هذا الميناء بوابة تاريخية للتجارة البحرية وموطناً للعديد من الصينيين المغتربين.'),
  'baoding/mansion': ('قصر الحاكم', 'يُعتبر هذا القصر أعلى مقر إداري إقليمي في عهد أسرة تشينغ، وهو قاعة حكم محفوظة بشكل جيد.'),
  'baoding/donkeyburger': ('شطيرة لحم الحمير', 'تُعد هذه الشطيرة المكونة من لحم الحمير المتبل داخل خبز مقرمش أشهر مأكولات الشارع في المنطقة.'),
  'baoding/balls': ('كرات الصحة', 'تُعد ممارسة تدوير كرات معدنية في راحة اليد تقليداً قديماً يعود لقرون مضت لتعزيز صحة اليدين.'),
  'baoding/reeds': ('مستنقعات باييانغديان', 'تُعد أكبر منطقة رطبة في شمال الصين، وهي ملاذ للطيور وسط نباتات القصب وزهور اللوتس.'),
  'jilin/rime': ('صقيع جيلين', 'تُعتبر طبقة الصقيع الأبيض التي تغطي الأشجار على ضفاف نهر سونغهوا واحدة من عجائب الطبيعة الأربع في الصين.'),
  'jilin/snowboard': ('منتجع التزلج', 'بفضل ثلوجها العميقة وموسمها الطويل، تُعد المدينة واحدة من أفضل وجهات التزلج في شمال البلاد.'),
  'jilin/meteorite': ('متحف النيازك', 'يضم المتحف أكبر نيزك صخري في العالم، والذي سقط على الأرض في عام 1976.'),
  'jilin/skate': ('نهر سونغهوا المتجمد', 'يتحول نهر سونغهوا في فصل الشتاء إلى حلبة تزلج طبيعية يرتادها المتزلجون والمتنزهون.'),
  'ordos/khan': ('ضريح جنكيز خان', 'يُعد الضريح المهيب الذي يخلد ذكرى بطل السهوب جنكيز خان قلب الثقافة المغولية.'),
  'ordos/cashmere': ('الكشمير', 'يضع الكشمير المنسوج من صوف ماعز أوردوس المدينة في صدارة صناعة المنسوجات العالمية.'),
  'ordos/sanddune': ('الرمال الغنائية', 'تُعد الكثبان الرملية العملاقة التي تصدر طنيناً عند الانزلاق عليها الوجهة المفضلة في صحراء كوبوتشي.'),
  'ordos/yurt': ('الخيمة المغولية', 'ترمز الخيام المصنوعة من اللباد الأبيض والمنصوبة في المراعي الشاسعة إلى نمط الحياة البدوي.'),
  'jining/confucius': ('معبد كونفوشيوس', 'يقع المعبد وقصر وضريح الحكيم كونفوشيوس في مدينة تشوفو المجاورة، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'jining/barge': ('القناة الكبرى', 'باعتبارها ميناءً نشطاً على قناة بكين-هانغتشو، كانت جينينغ مركزاً حيوياً لثقافة القنوات المائية.'),
  'jining/sword': ('أبطال ليانغشان', 'تجمع مئة وثمانية من الأبطال الخارجين عن القانون في هذه التلال المستنقعية، وفقاً لما ورد في رواية "حافة الماء" الكلاسيكية.'),
  'jining/fishnet': ('بحيرة ويشان', 'يلقي الصيادون شباكهم بالطرق التقليدية القديمة في أكبر بحيرة للوتس في شمال الصين.'),
  'langfang/culture': ('مركز ثقافة طريق الحرير', 'يجمع هذا المركز الثقافي الحديث والضخم في المدينة فنون طريق الحرير تحت سقف واحد.'),
  'langfang/furniture': ('مدينة الأثاث', 'تُعد منطقة شيانغخه المجاورة واحدة من أكبر مراكز تصنيع وتجارة الأثاث في الصين.'),
  'langfang/tunnel': ('أنفاق الحرب القديمة', 'تمتد هذه الأنفاق العسكرية التي حُفرت تحت الأرض منذ ألف عام لتشكل خط دفاع حدودي قديم.'),
  'langfang/themepark': ('منتزه المدينة رقم 1', 'يستقبل هذا المنتزه الترفيهي الواسع العائلات، حيث يعيد تجسيد مدينة قديمة مسورة.'),
  'yancheng/salt': ('مدينة الملح', 'يعني اسم يانتشنغ "حصن الملح"، حيث كانت لقرون مركزاً رئيسياً لإنتاج الملح في الصين.'),
  'yancheng/crane': ('الكركي أحمر التاج', 'تعتبر هذه الأراضي الرطبة الساحلية أكبر منطقة شتوية في العالم للكركي أحمر التاج البري.'),
  'yancheng/elk': ('أيل الأب ديفيد', 'بعد أن انقرض أيل الميلو في البرية، عاد للتكاثر والعيش مجدداً في هذه الأراضي الرطبة.'),
  'yancheng/wetland': ('الأراضي الرطبة الساحلية', 'تُعد المسطحات المدية المدرجة ضمن قائمة اليونسكو محطة عالمية للطيور المهاجرة.'),
  'huzhou/brush': ('فرشاة هو للخط', 'تُصنع هنا فرشاة "هو"، التي تُعد واحدة من "الكنوز الأربعة" للخط الصيني التقليدي.'),
  'huzhou/bamboo': ('بحر خيزران أنجي', 'تساهم غابات الخيزران الخضراء الممتدة، التي كانت مصدراً لإلهام العديد من الأفلام، في تلطيف درجات الحرارة.'),
  'huzhou/silkworm': ('دودة القز', 'لطالما كان الشاطئ الجنوبي لبحيرة تاي مركزاً لإنتاج حرير التوت منذ ألف عام.'),
  'huzhou/whitetea': ('شاي أنجي الأبيض', 'يُعد شاي أنجي الأبيض، بأوراقه الشاحبة ومذاقه الحلو، من بين أندر أنواع الشاي في الصين.'),
  'quzhou/go': ('لعبة غو', 'تُبجل المدينة باعتبارها "أرض الغو"، وذلك بفضل الأسطورة الشهيرة المرتبطة بجبل لانكي.'),
  'quzhou/peaks': ('جبل جيانغلانغ', 'تشكل الأعمدة الصخرية الثلاثة الضخمة التي تعانق السماء مشهداً طبيعياً فريداً مدرجاً ضمن قائمة اليونسكو.'),
  'quzhou/ponkan': ('يوسفي تشوتشو', 'يُعد اليوسفي ذو القشرة الحلوة هدية الشتاء التي تجود بها التلال المعتدلة في المنطقة.'),
  'quzhou/cake': ('خبز السمسم المخبوز', 'يُعتبر خبز السمسم المقرمش المخبوز على جدران الفرن وجبة إفطار تقليدية شهيرة في المدينة.'),
  'huainan/tofu': ('مهد التوفو', 'ابتُكر التوفو على جبل باغونغ قبل ألفي عام، ومن هنا انتشر ليصبح جزءاً من المطبخ العالمي.'),
  'huainan/coalmine': ('مدينة الفحم', 'تُعد هواينان قاعدة طاقة رئيسية في شرق الصين بفضل غناها بطبقات الفحم الوفيرة.'),
  'huainan/oldtown': ('مدينة شو القديمة', 'يُعد سور المدينة المحفوظ بالكامل من عهد أسرة سونغ نموذجاً نادراً للتصميم الدفاعي القديم.'),
  'huainan/classic': ('كتاب هواينانزي', 'كُتب هذا المؤلف الفلسفي الكلاسيكي، الذي جمعه الأمير ليو آن، على هذه الأراضي.'),
  'jingdezhen/porcelain': ('عاصمة الخزف', 'تُلقب المدينة بعاصمة الخزف في العالم، حيث ظلت تنتج الخزف الإمبراطوري لأكثر من ألف عام.'),
  'jingdezhen/kiln': ('الأفران القديمة', 'تحافظ أفران التنين التي تعمل بالحطب على استمرارية فن حرق الخزف التقليدي حتى يومنا هذا.'),
  'jingdezhen/bluewhite': ('الخزف الأزرق والأبيض', 'يُعد الخزف الأبيض المزين بنقوش زرقاء من الكوبالت العلامة التجارية الشهيرة للمدينة عالمياً.'),
  'jingdezhen/painting': ('الرسم على الخزف', 'تُقدر القطع الخزفية التي يرسمها كبار الفنانين بفرشاة دقيقة كأنها لوحات فنية نفيسة.'),
  'jian/jinggang': ('جبال جينغغانغ', 'تُعتبر هذه الجبال الضبابية، التي كانت أول قاعدة للثورة، قلب السياحة الحمراء في الصين.'),
  'jian/torch': ('شرارة الثورة', 'تُعد هذه الأرض التي شهدت ولادة مقولة "شرارة واحدة يمكن أن تشعل سهلاً" نصباً تذكارياً تاريخياً هاماً.'),
  'jian/academy': ('أكاديمية بايلوتشو', 'خرجت هذه الأكاديمية التي يعود تاريخها لألف عام، والواقعة على جزيرة في نهر غان، عدداً لا يحصى من العلماء الإمبراطوريين.'),
  'jian/pine': ('صنوبر جينغغانغ', 'ترمز أشجار الصنوبر الحمراء التي ترتفع وسط الضباب إلى روح الجبل والصمود.'),
  'nanping/wuyi': ('جبال وويي', 'تُعد هذه الجبال المدرجة ضمن قائمة اليونسكو كنزاً طبيعياً وثقافياً بفضل منحدراتها الحمراء ووديانها الخضراء.'),
  'nanping/rocktea': ('شاي الصخور', 'يُعتبر شاي أولونغ "الرداء الأحمر الكبير" الذي ينمو بين الصخور من أغلى أنواع الشاي في العالم.'),
  'nanping/bambooraft': ('طوافات النهر المتعرج', 'تنساب طوافات الخيزران بهدوء عبر مجرى النهر المتعرج بين المنحدرات الصخرية الحمراء.'),
  'nanping/scholar': ('المعلم تشو شي', 'درّس تشو شي، مؤسس الكونفوشيوسية الجديدة، عند سفح هذه الجبال.'),
  'shenzhen/skyscraper': ('ناطحات السحاب', 'تُعد غابة ناطحات السحاب التي نشأت من قرية صيد خلال أربعين عاماً معجزة الإصلاح في الصين.'),
  'shenzhen/chip': ('مدينة التكنولوجيا', 'تُلقب شينزين بـ "وادي السيليكون الصيني" بفضل سوق هواكيانغبي للإلكترونيات وشركات التكنولوجيا العملاقة.'),
  'shenzhen/miniature': ('نافذة على العالم', 'تُعد هذه الحديقة الترفيهية التي تضم نماذج مصغرة لأشهر معالم العالم أيقونةً للمدينة.'),
  'shenzhen/mangrove': ('خليج شينزين', 'يُعتبر الخليج المليء بأشجار المانغروف ملاذاً آمناً للطيور المهاجرة وطيور البلشون.'),
  'xian/terracotta': ('جيش الطين', 'يُطلق على آلاف الجنود الطينيين الذين يحرسون ضريح الإمبراطور تشين لقب أعجوبة العالم الثامنة.'),
  'xian/citywall': ('سور المدينة', 'يُعد سور مدينة شيان من عهد أسرة مينغ الأفضل حفظاً في الصين، ويمكن استكشافه بركوب الدراجات الهوائية فوق حصونه.'),
  'xian/drumtower': ('برج الجرس', 'يمثل برج الجرس الذي يعود لعهد أسرة مينغ في وسط المدينة قلب العاصمة القديمة.'),
  'xian/roujiamo': ('روجيامو', 'تُعد "روجيامو"، وهي عبارة عن لحم متبل محشو في خبز مقرمش، النسخة الأصلية من البرغر على طريق الحرير.'),
  'suzhou/garden': ('الحدائق الكلاسيكية', 'تُعد هذه الحدائق المدرجة ضمن قائمة اليونسكو تحفاً فنية مصممة بعناية مع الصخور والبرك والأجنحة.'),
  'suzhou/watertown': ('المدينة المائية', 'تُلقب سوتشو بـ "فينيسيا الشرق" بفضل قنواتها المائية وجسورها الحجرية ومنازلها البيضاء.'),
  'suzhou/embroidery': ('تطريز سوتشو', 'يُعد التطريز الحريري مزدوج الوجه حرفة تقليدية في سوتشو يعود تاريخها إلى ألف عام.'),
  'suzhou/kunqu': ('أوبرا كونتشو', 'تُعد أوبرا كونتشو الأنيقة، التي تُعتبر الأم لجميع أنواع الأوبرا الصينية، المهد الفني الذي نشأت فيه.'),
  'kunming/stoneforest': ('الغابة الحجرية', 'تشكل أعمدة الحجر الجيري العملاقة، التي نُحتت عبر ملايين السنين، متاهة حجرية غامضة.'),
  'kunming/springcity': ('مدينة الربيع', 'بفضل مناخها المعتدل طوال العام، تُلقب كونمينغ بـ "مدينة الربيع" حيث لا تذبل الزهور أبداً.'),
  'kunming/seagull': ('نوارس الرأس الأسود', 'في كل شتاء، تهاجر آلاف النوارس من سيبيريا لتكسو ضفاف البحيرة باللون الأبيض.'),
  'kunming/ricenoodle': ('نودلز عبور الجسر', 'تُعد نودلز الأرز الرفيعة التي تُضاف إلى المرق الساخن عند التقديم الطبق الأشهر في مقاطعة يونان.'),
  'jinan/spring': ('مدينة الينابيع', 'تستمد جينان لقبها "مدينة الينابيع" من ينابيعها الاثنتين والسبعين الشهيرة التي تتدفق من باطن الأرض.'),
  'jinan/daminglake': ('بحيرة دامينغ', 'تتغذى هذه البحيرة الحضرية، التي تحيط بها أشجار الصفصاف وزهور اللوتس، من مياه الينابيع الطبيعية.'),
  'jinan/buddhamountain': ('جبل بوذا الألف', 'يُعد الجبل وجهة للحج بفضل مئات تماثيل بوذا المنحوتة على منحدراته.'),
  'jinan/poet': ('الشاعرة لي تشينغ تشاو', 'وُلدت لي تشينغ تشاو، أعظم شاعرة في تاريخ الصين، في هذه المدينة التي تُعرف بمدينة الينابيع.'),
  'ningbo/library': ('مكتبة تياني', 'تُعد مكتبة تياني، التي يعود تاريخها إلى 450 عاماً، أقدم مكتبة خاصة لا تزال قائمة في آسيا.'),
  'ningbo/port': ('ميناء الشحن', 'يُصنف ميناء نينغبو-تشوشان كأكثر موانئ العالم ازدحاماً من حيث حمولة البضائع.'),
  'ningbo/tangyuan': ('كرات الأرز الدبق', 'تُعتبر كرات الأرز الدبق المحشوة بالسمسم، المعروفة باسم "تانغ يوان"، الحلوى التقليدية المميزة للمدينة.'),
  'ningbo/seafood': ('المأكولات البحرية', 'تعتمد المائدة المحلية في نينغبو بشكل أساسي على أسماك الكروكر الصفراء وسرطان البحر المستخرج من بحر الصين الشرقي.'),
  'shijiazhuang/bridge': ('جسر تشاوتشو', 'يُعد هذا الجسر الحجري المقوس، الذي يبلغ عمره 1400 عام، أقدم جسر ذي فتحات مفتوحة في العالم.'),
  'shijiazhuang/clifftemple': ('جبل تسانغيان', 'يُعتبر المعبد المعلق بين المنحدرات الصخرية خلفية شهيرة للعديد من الأعمال السينمائية.'),
  'shijiazhuang/redbase': ('قاعدة شيبايبو', 'تعد هذه القرية، التي وُضعت فيها خطط تأسيس الصين الجديدة، وجهة مقدسة للسياحة الحمراء.'),
  'shijiazhuang/pharma': ('مدينة الأدوية', 'تُعتبر المدينة مركزاً رئيسياً لإنتاج المضادات الحيوية، وتضم واحدة من أكبر شركات تصنيع الأدوية في الصين.'),
  'taiyuan/jincitemple': ('معبد جينسي', 'يُعد معبد جينسي بحدائقه وتماثيله وينابيعه التي يعود تاريخها إلى ثلاثة آلاف عام، أكثر معابد شمال الصين أناقةً.'),
  'taiyuan/coalcart': ('أرض الفحم', 'تُعد مدينة تاييوان عاصمة الثروة المعدنية في مقاطعة شانشي، حيث تمد طبقات الفحم فيها الصين بالطاقة.'),
  'taiyuan/vinegar': ('الخل المعتق', 'يُعتبر الخل المعتق المكون الأساسي الذي يمنح المطبخ في مقاطعة شانشي مذاقه الحامض المميز.'),
  'taiyuan/twinpagoda': ('الباغودا التوأم', 'تنتصب هاتان الباغودتان المثمنتان اللتان تعودان إلى عهد أسرة مينغ جنباً إلى جنب كرمزٍ لمدينة تاييوان.'),
  'hohhot/lamatemple': ('معبد داتشاو', 'يُعد هذا الدير البوذي التبتي، المشهور بتمثال بوذا الفضي، القلب الروحي لمدينة هوهوت.'),
  'hohhot/dairy': ('عاصمة الألبان', 'تُلقب المدينة بعاصمة الحليب، حيث نشأت فيها أكبر العلامات التجارية لمنتجات الألبان في الصين.'),
  'hohhot/wrestling': ('المصارعة المنغولية', 'تُعد مصارعة "بوخ"، التي تمثل ذروة مهرجان نادام، استعراضاً لقوة أهل السهوب.'),
  'hohhot/prairie': ('المراعي', 'تمتد خارج المدينة مراعي منغوليا الخضراء الشاسعة، المليئة بالخيول وقطعان الماشية.'),
  'sanya/resortbeach': ('الشاطئ الاستوائي', 'تُشبه رمال خليج يالونغ الناعمة ومياهه الفيروزية جزر هاواي في الصين.'),
  'sanya/guanyin': ('تمثال غوانيين', 'يُعد تمثال غوانيين، الذي يرتفع 108 أمتار فوق سطح البحر، واحداً من أطول تماثيل الآلهة في العالم.'),
  'sanya/diving': ('الغوص', 'تُعتبر سانيا جنة الغوص في الصين بفضل مياهها الدافئة والصافية وشعابها المرجانية.'),
  'sanya/coconutdrink': ('جوز الهند', 'يُعد ماء جوز الهند الطازج المستخرج من البساتين الاستوائية المشروب المنعش والمفضل في الجزيرة.'),
  'yangzhou/slenderlake': ('بحيرة الغرب النحيلة', 'تتسم هذه البحيرة بأشجار الصفصاف وجسرها الأبيض، مما يضفي عليها جمالاً يشبه اللوحات الفنية.'),
  'yangzhou/friedrice': ('أرز يانغتشو المقلي', 'يُعد هذا الطبق الكلاسيكي الشهير عالمياً مزيجاً ذهبياً من الأرز المقلي مع الروبيان والبيض.'),
  'yangzhou/morningtea': ('شاي الصباح', 'تعتبر طقوس تناول وجبة إفطار أنيقة تتكون من الكعك المطهو على البخار والشاي جزءاً أصيلاً من ثقافة مدينة يانغتشو.'),
  'yangzhou/gegarden': ('حديقة غي', 'تُعد هذه الحديقة التي تضم تشكيلات صخرية تحاكي فصول السنة الأربعة تحفة فنية في التصميم الكلاسيكي.'),
  'weihai/navalisland': ('جزيرة ليوقونغ', 'بصفتها القاعدة السابقة لأسطول بييانغ، تشهد هذه الجزيرة على التاريخ البحري للصين الحديثة.'),
  'weihai/swan': ('بحيرة البجع', 'تتوافد مئات طيور البجع الصامت من سيبيريا كل شتاء لتستقر في هذه البحيرة الساحلية.'),
  'weihai/seacucumber': ('خيار البحر', 'يُعتبر خيار البحر الذي ينمو في المياه الباردة والنقية أثمن المأكولات البحرية في المدينة.'),
  'weihai/cape': ('رأس الصين', 'يُعد هذا الرأس الواقع في أقصى شرق الصين المكان الذي تستقبل فيه البلاد خيوط الشمس الأولى.'),
  'handan/taichi': ('تاي تشي', 'تُعتبر بلدة غوانغفو مهد أسلوبي يانغ وو، وهي الموطن الأصلي لرياضة التاي تشي.'),
  'handan/congtai': ('شرفة كونغتاي', 'تطل هذه الشرفة الترابية التي تعود إلى مملكة تشاو القديمة على أكثر من ألفي عام من التاريخ.'),
  'handan/idiom': ('مدينة الأمثال', 'تُلقب هاندان بمدينة الأمثال، حيث نشأ فيها أكثر من ألف وخمسمائة مثل صيني شهير.'),
  'handan/ciporcelain': ('خزف تسيجو', 'يُعد خزف تسيجو الذي يتميز بنقوش سوداء على خلفية بيضاء نموذجاً كلاسيكياً للسيراميك الشعبي.'),
  'daqing/oilpump': ('حقل النفط', 'تنتشر مضخات النفط المتأرجحة في أرجاء أكبر حقل نفطي في الصين.'),
  'daqing/oilworker': ('الرجل الحديدي', 'تجسد عزيمة بطل عمال النفط وانغ جينشي الروح التأسيسية لهذه المدينة.'),
  'daqing/reedlake': ('الأراضي الرطبة', 'تعد البحيرات المليئة بالقصب وسط آبار النفط موطناً طبيعياً لطيور الكركي والبجع.'),
  'daqing/hotspring': ('الينابيع الحارة', 'توفر المياه المعدنية الساخنة القادمة من باطن الأرض استراحة علاجية دافئة في شمال البلاد البارد.'),
  'zibo/bbq': ('مشويات تسيبو', 'تُعد هذه المشويات، التي تُقدم على مواقد صغيرة وتُلف في فطائر رقيقة، ظاهرة غذائية اجتاحت أرجاء الصين.'),
  'zibo/cuju': ('تسو جو', 'تُعتبر "تسو جو" أقدم شكل من أشكال كرة القدم في العالم، وقد كانت تُمارس في مدينة لينزي، عاصمة ولاية تشي القديمة.'),
  'zibo/ceramic': ('خزف تسيبو', 'بفضل أفرانها التي يعود تاريخها إلى آلاف السنين، تُعد المدينة مركزاً رئيسياً لصناعة الخزف في شمال الصين.'),
  'zibo/glass': ('الزجاج الملون', 'يُعد "ليولي"، وهو زجاج ملون يُصنع يدوياً من الزجاج المنصهر، حرفة فنية تتلألأ ببريق أخاذ.'),
  'taian/mounttai': ('جبل تاي', 'يُعتبر جبل تاي سيد الجبال الخمسة المقدسة، وهو أقدس قمة كان الأباطرة يقدمون عندها القرابين للسماء.'),
  'taian/sunrise': ('شروق الشمس من القمة', 'تُعد مشاهدة شروق الشمس فوق بحر من السحب المكافأة الكبرى لمن يتسلق جبل تاي.'),
  'taian/stonesteps': ('الدرج الحجري', 'تمثل السلالم الحجرية التي يبلغ عددها سبعة آلاف درجة الاختبار البدني الحقيقي في طريق الحجاج نحو القمة.'),
  'taian/daitemple': ('معبد داي', 'يُعد هذا المعبد المهيب الواقع عند سفح الجبل المكان الذي كان الأباطرة يستعدون فيه لإقامة طقوس جبل تاي.'),
  'lianyungang/monkey': ('جبل ملك القردة', 'يحتضن جبل هواغو موطن ملك القردة الشهير في رواية "رحلة إلى الغرب".'),
  'lianyungang/seaport': ('الميناء البحري', 'يُعد الميناء البوابة البحرية الشرقية لطريق الحرير، وهو الطرف المطل على المحيط الهادئ للجسر البري الأوراسي.'),
  'lianyungang/mountain': ('جبل يونتاي', 'بقممه الشاهقة وغاباته الكثيفة، يُعتبر جبل يونتاي أعلى جبل في مقاطعة جيانغسو.'),
  'lianyungang/crystal': ('أرض الكريستال', 'تستضيف منطقة دونغهاي المجاورة واحدة من أكبر أسواق بلورات الكوارتز في العالم.'),
  'maanshan/libai': ('الشاعر لي باي', 'تضم هذه المدينة الواقعة على ضفاف النهر المحطة الأخيرة وضريح أعظم شاعر في تاريخ الصين، لي باي.'),
  'maanshan/steel': ('مدينة الصلب', 'ساهمت مصانع "ماغانغ" للصلب في جعل المدينة واحدة من أهم القواعد الصناعية للحديد والصلب في الصين.'),
  'maanshan/rivercliff': ('جرف تسايشيجي', 'يُعد الجرف الذي يغوص في مياه نهر اليانغتسي المشهد الشعري الذي ارتبط بأسطورة الشاعر لي باي.'),
  'maanshan/moonwine': ('القمر والنبيذ', 'لا تزال قصائد لي باي التي تتغنى بالقمر والنبيذ تُحتفى بها في المهرجانات المقامة على ضفاف النهر.'),
  'longyan/tulou': ('بيوت التولو في يونغدينغ', 'تُعد هذه القلاع السكنية الدائرية الضخمة التي بناها شعب الهاكا في التلال من مواقع التراث العالمي لليونسكو.'),
  'longyan/redmeeting': ('اجتماع غوتيان', 'عُقد في هذه القرية الاجتماع التاريخي الذي رسم مسار الجيش الأحمر.'),
  'longyan/hakka': ('ثقافة الهاكا', 'يحافظ شعب الهاكا، وهم مهاجرون من الشمال، على لغتهم ومأكولاتهم التقليدية في هذه التلال.'),
  'longyan/mountain': ('جبل غوانتشي', 'يُعتبر هذا الجبل، بمنحدراته الحمراء وبركه الصافية، الجوهرة الطبيعية لجنوب مقاطعة فوجيان.'),
  'sanming/danxia': ('تضاريس دانكسيا في تاينينغ', 'تُشكل هذه الحديقة الجيولوجية المدرجة ضمن اليونسكو متاهة من الصخور المتساقطة من السماء، وتتميز بمنحدراتها الحمراء ووديانها العميقة.'),
  'sanming/shaxian': ('وجبات شا شيان الخفيفة', 'انتشرت وجبات شا شيان الخفيفة، مثل الوانتون والمعكرونة المخلوطة بأسعارها الزهيدة، في جميع أنحاء الصين.'),
  'sanming/forest': ('العاصمة الخضراء', 'تُعد سانمينغ أكثر مدن الصين تشجيراً، وتتميز بهوائها النقي وجبالها الخضراء.'),
  'sanming/goldenlake': ('البحيرة الذهبية', 'تمتد هذه البحيرة بين منحدرات دانكسيا، ويمكن استكشافها عبر القوارب.'),
  'ningde/mudflat': ('مسطحات شيا بو الطينية', 'تُعد المسطحات المدية المتلألئة التي تتغير مع حركة البحر من بين أكثر الشواطئ التي يتم تصويرها في العالم.'),
  'ningde/whitetea': ('شاي فودينغ الأبيض', 'يُصنع هذا الشاي من براعم مغطاة بالزغب، وتزداد قيمته كلما تقدم في العمر.'),
  'ningde/taimu': ('جبل تايمو', 'يُعرف هذا الجبل بقممه الجرانيتية وكهوفه المطلة على البحر، ويُلقب بـ "أرض العجائب البحرية".'),
  'ningde/croaker': ('سمك الكروكر الأصفر', 'يُعتبر سمك الكروكر الأصفر الكبير، الذي يُربى في الخلجان المحمية، كنز المدينة البحري.'),
  'shaoguan/redcliff': ('جبل دانكسيا', 'يشتهر هذا الجبل الصخري الأحمر، الذي سُميت تضاريس "دانكسيا" باسمه، بأعمدته الصخرية المنحوتة.'),
  'shaoguan/chantemple': ('معبد نانهوا', 'يُعد هذا المعبد مركزاً مقدساً لبوذية تشان، وهو المكان الذي عاش فيه هوي نينغ، البطريرك السادس للديانة.'),
  'shaoguan/ancestor': ('زقاق تشوجي', 'يُعد هذا الزقاق مهد الجذور الذي يتتبع منه ملايين الصينيين في الجنوب أصول أسلافهم المهاجرين.'),
  'shaoguan/yaodance': ('شعب ياو', 'يشتهر شعب ياو، الذي يسكن القرى الجبلية، بأزيائهم الملونة ورقصاتهم التقليدية على أنغام الطبول.'),
  'zhanjiang/oyster': ('محار تشانجيانغ', 'يُشوى المحار الممتلئ الذي ينمو في المياه الجنوبية الدافئة على الفحم ليُقدم كطبق شهي على المائدة.'),
  'zhanjiang/navy': ('الميناء البحري', 'يُعتبر هذا الميناء العميق، الذي يضم أسطول بحر الصين الجنوبي، البوابة البحرية الجنوبية للبلاد.'),
  'zhanjiang/mangrove': ('غابات المانغروف', 'تُعد أكبر غابة مانغروف في الصين ملاذاً آمناً لطيور البلشون والسلطعونات في مياهها المدية.'),
  'zhanjiang/donghai': ('جزيرة دونغهاي', 'بفضل شاطئها الطويل ورياحها المستقرة، تُعد الجزيرة وجهة مفضلة للاستمتاع بحمامات الشمس وركوب الأمواج.'),
  'maoming/lychee': ('عاصمة الليتشي', 'تُعد ماومينغ أكبر منتج لفاكهة الليتشي في الصين، وهي الأرض التي كانت تُرسل هذه الثمار للأباطرة قديماً.'),
  'maoming/refinery': ('قاعدة البتروكيماويات', 'تُشكل واحدة من أكبر مصافي النفط في جنوب الصين الركيزة الأساسية للقوة الصناعية للمدينة.'),
  'maoming/ladyxian': ('السيدة شيان', 'تحظى السيدة شيان، البطلة التي وحدت الجنوب، بتقدير وتكريم الشعب منذ ألف عام.'),
  'maoming/seaside': ('شاطئ البحر', 'يُعرف هذا الشاطئ الطويل بلقب \'شاطئ الصين الأول\'، ويوفر للعائلات رمالاً ذهبية خلابة.'),
  'zhaoqing/sevenstar': ('صخور النجوم السبع', 'تُلقب صخور الحجر الجيري السبع التي ترتفع من وسط البحيرة بـ \'غويلين غوانغدونغ\'.'),
  'zhaoqing/inkstone': ('حجر حبر دوان', 'يُصنع حجر حبر دوان، أحد كنوز الخط الأربعة، في هذه المنطقة منذ ألف عام.'),
  'zhaoqing/dinghu': ('جبل دينغهو', 'يُعتبر أول محمية طبيعية في الصين، وهو \'منتجع أكسجين\' حي يضم غابات مطيرة وشلالات مورقة.'),
  'zhaoqing/songwall': ('سور مدينة سونغ', 'يحيط السور المحفوظ بالكامل من عهد أسرة سونغ بمدينة تشاوتشينغ القديمة كحلقة من التاريخ.'),
  'huizhou/westlake': ('بحيرة هويتشو الغربية', 'تُعد البحيرة، التي أحبها الشاعر المنفي سو شي، قصيدة غنائية من أشجار الصفصاف والجسور الممتدة.'),
  'huizhou/luofu': ('جبل لووفو', 'يُعد هذا الجبل موطناً لنساك الطاوية والأعشاب الطبية، ويُصنف كواحد من أول القمم المقدسة في جنوب الصين.'),
  'huizhou/alchemy': ('خيمياء غي هونغ', 'وضع الطبيب والخيميائي غي هونغ أسس الطب التقليدي أثناء إقامته على هذا الجبل.'),
  'huizhou/xunliao': ('خليج شونلياوه', 'بمياهه الصافية ورماله الناعمة، يُعتبر هذا الخليج ملاذاً هادئاً على الساحل الجنوبي.'),
  'meizhou/weilongwu': ('عاصمة الهاكا', 'تُعرف مدينة ميتشو بكونها عاصمة الهاكا العالمية، وتشتهر بمنازلها التقليدية ذات التصميم الذي يشبه حدوة الحصان.'),
  'meizhou/saltchicken': ('الدجاج المخبوز بالملح', 'يُعد الدجاج المخبوز المدفون في الملح الساخن طبقاً مميزاً من مطبخ الهاكا، ويتميز بلحمه الطري والشهي.'),
  'meizhou/football': ('موطن كرة القدم', 'تُعتبر المدينة مهد كرة القدم الصينية، وقد خرّجت أجيالاً من اللاعبين النجوم على مر السنين.'),
  'meizhou/plum': ('زهرة البرقوق', 'تتزين المدينة، التي يعني اسمها البرقوق، بزهور البرقوق الجميلة خلال فصل الشتاء.'),
  'jiangmen/diaolou': ('أبراج كايبينغ دياولو', 'هي أبراج حصينة متعددة الطوابق بناها المهاجرون العائدون، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'jiangmen/qiaoxiang': ('موطن الصينيين المغتربين', 'تُعد هذه المدينة مسقط رأس ملايين الصينيين المغتربين، وتتميز بمزيج فريد بين الثقافتين الشرقية والغربية.'),
  'jiangmen/chenpi': ('قشور اليوسفي المجففة', 'تُستخدم قشور يوسفي شينهوي المعتقة كتوابل فاخرة وكعلاج طبي ذي قيمة عالية.'),
  'jiangmen/birds': ('جنة الطيور', 'تضم هذه المنطقة بستاناً تشكل من شجرة تين بنغالي عملاقة واحدة، وتعد موطناً لعشرات الآلاف من طيور البلشون.'),
  'yangjiang/knife': ('عاصمة السكاكين', 'تُصنع هنا نسبة كبيرة من سكاكين المطبخ الصينية وفق تقاليد عريقة في الحدادة تعود لقرون مضت.'),
  'yangjiang/shipwreck': ('حطام نانهاي رقم 1', 'يُعرض هذا الحطام لسفينة من عهد أسرة سونغ، التي كانت تجوب طريق الحرير البحري، مع كنوزها في متحف تحت الماء.'),
  'yangjiang/hailing': ('جزيرة هايلينغ', 'بفضل شواطئها المشمسة وأمواجها، تُعد الجزيرة الوجهة الساحلية المفضلة في مقاطعة غوانغدونغ.'),
  'yangjiang/kite': ('مدينة الطائرات الورقية', 'تُعد المدينة واحدة من عاصمتي الطائرات الورقية في الصين إلى جانب ويفانغ، وتملأ طائراتها سماء الخريف.'),
  'qingyuan/rafting': ('عاصمة التجديف', 'تُلقب مدينة تشينغيوان بـ "موطن التجديف" في الصين بفضل جداولها الجبلية المتدفقة.'),
  'qingyuan/chicken': ('دجاج تشينغيوان', 'يُعد هذا النوع المحلي من الدجاج، المعروف بعظامه الدقيقة ومذاقه الغني، الطبق الأكثر طلباً على المائدة الكانتونية.'),
  'qingyuan/hotspring': ('الينابيع الحارة', 'تُشكل المياه المعدنية الحارة القادمة من الوديان الجبلية الوجهة المفضلة لقضاء عطلات نهاية الأسبوع.'),
  'qingyuan/yaoterrace': ('مصاطب ياو الزراعية', 'تعتبر هذه المصاطب التي حفرها شعب الياو في لياننان على سفوح الجبال تجسيداً لقرون من الكد والعمل.'),
  'chaozhou/guangjibridge': ('جسر غوانغجي', 'يُعد هذا الجسر القديم، الذي يتميز بوسطه القابل للفتح والإغلاق لمرور القوارب، واحداً من أشهر أربعة جسور في الصين.'),
  'chaozhou/woodcarving': ('النحت الخشبي المذهب', 'تتألق المعابد بجمال المنحوتات الخشبية متعددة الطبقات والمغطاة بورق الذهب.'),
  'chaozhou/chaoxiu': ('تطريز تشاوتشو', 'يُعتبر تطريز تشاوتشو، بخيوطه الذهبية البارزة، أكثر أنواع التطريز فخامة في جنوب الصين.'),
  'chaozhou/kaiyuan': ('معبد كايوان', 'يُشكل هذا المعبد الذي يعود تاريخه إلى 1200 عام، بساحاته الهادئة التي تعود لعصر أسرة تانغ، قلب المدينة النابض.'),
  'jieyang/citygate': ('بوابة جينشيان', 'تُعد هذه البوابة الخشبية الأنيقة المطلة على النهر الرمز التاريخي الباقي لمدينة جييانغ القديمة.'),
  'jieyang/jade': ('عاصمة اليشم', 'تُعد بلدة يانغماي واحدة من أكبر مراكز نحت وتجارة اليشم في الصين.'),
  'jieyang/jieyanglou': ('برج جييانغ', 'يُعد هذا البرج الضخم ذو الأفاريز التقليدية نصباً تذكارياً حديثاً يحتفي بثقافة تشاوشان.'),
  'jieyang/beefbroth': ('مرق لحم البقر على طريقة تشاوشان', 'يُعتبر لحم البقر الطازج المسلوق في مرق صافٍ الطبق الأكثر تميزاً في المنطقة.'),
  'yunfu/marble': ('مملكة الحجر', 'تُعد مدينة يونفو عاصمة صناعة الرخام والحجر، وتصدر منتجاتها الحجرية المصقولة إلى جميع أنحاء العالم.'),
  'yunfu/patriarch': ('المعلم السادس', 'تُعد هذه الأرض مسقط رأس معلم طائفة "تشان" هوي نينغ، وتكتسب قدسيتها من معبد غو-إن.'),
  'yunfu/tianlu': ('جبل تيانلو', 'يُعتبر الجبل، بقممه التي تلامس السحاب وحدائق الشاي، التاج الأخضر للمدينة.'),
  'yunfu/xijiang': ('نهر شيجيانغ', 'يعد هذا النهر الشريان المائي الرئيسي لنهر اللؤلؤ في جنوب الصين، حيث يتدفق عبر المدينة.'),
  'liuzhou/luosifen': ('نودلز الحلزون', 'تعد نودلز الحلزون ذات المذاق الحامض والحار ظاهرة غذائية تجتاح جميع أنحاء الصين.'),
  'liuzhou/autocity': ('مدينة السيارات', 'بفضل إنتاجها للسيارات الصغيرة التي يفضلها السكان، تُعد مدينة ليوتشو واحدة من أكبر مراكز صناعة السيارات في الصين.'),
  'liuzhou/karst': ('تضاريس كارست في نهر ليو', 'تضفي التلال الكلسية ومنعطف النهر الذي يحيط بالمدينة جمالاً طبيعياً خلاباً على هذه المدينة الصناعية.'),
  'liuzhou/liuhou': ('الشاعر ليو تسونغ يوان', 'تخلد حديقة المدينة ذكرى الشاعر والحاكم في عهد أسرة تانغ، ليو تسونغ يوان، من خلال ضريح مخصص له.'),
  'wuzhou/gemstone': ('عاصمة الأحجار الكريمة', 'تُصقل نسبة هائلة من الأحجار الكريمة المصنعة في العالم داخل ورش هذه المدينة النهرية.'),
  'wuzhou/liubaotea': ('شاي ليوباو الداكن', 'يُعتبر شاي ليوباو الداكن المعتق مشروباً كلاسيكياً يساعد على الهضم في مناطق الجنوب الرطبة.'),
  'wuzhou/turtlejelly': ('هلام السلحفاة', 'يُعد هلام السلحفاة العشبي الأسود ذو المذاق المر وجبة خفيفة منعشة في الأيام الحارة.'),
  'wuzhou/dragonmother': ('معبد أم التنين', 'يُعد هذا المعبد المخصص لإلهة النهر \'أم التنين\' رمزاً للإيمان القديم لدى سكان المناطق النهرية.'),
  'beihai/silverbeach': ('الشاطئ الفضي', 'يمتد هذا الشاطئ الذي يُلقب بـ \'الشاطئ الأول تحت السماء\' لأميال بفضل رماله الناعمة المتلألئة.'),
  'beihai/pearl': ('مدينة اللؤلؤ', 'لطالما اعتُبر لؤلؤ بحر الجنوب في منطقة هيبو الأجود من نوعه منذ أيام تقديم الجزية للأباطرة.'),
  'beihai/weizhou': ('جزيرة ويزو', 'تجذب هذه الجزيرة البركانية، وهي الأحدث في الصين، الغواصين بفضل منحدراتها السوداء وشعابها المرجانية.'),
  'beihai/oldstreet': ('الشارع القديم', 'تحافظ المباني الاستعمارية ذات الأعمدة التي يعود تاريخها لقرن من الزمان على إرث ميناء طريق الحرير البحري.'),
  'qinzhou/nixingpottery': ('فخار نيكسينغ', 'يُعد فخار نيكسينغ، الذي تتغير ألوانه تلقائياً داخل الفرن، واحداً من أشهر أربعة أنواع من الخزف في الصين.'),
  'qinzhou/dolphin': ('الدلفين الأبيض', 'تُعد الدلافين البيضاء الصينية النادرة التي تسبح في خليج ساننيانغ الرمز المحبوب للمدينة.'),
  'qinzhou/oysterfarm': ('مزارع المحار', 'تُعد مدينة تشينتشو عاصمة المحار في الصين بفضل مزارع المحار العملاقة التي تنتشر في خلجانها الضحلة.'),
  'qinzhou/general': ('الجنرال فنغ تسيتساي', 'تزخر هذه المدينة بذكريات بطولية كونها مسقط رأس الجنرال المخضرم فنغ تسيتساي الذي دافع عن الحدود الصينية.'),
  'guigang/lotus': ('مدينة اللوتس', 'تُلقب غويغانغ بمدينة اللوتس نظراً لحقول اللوتس الشاسعة التي تتفتح فيها طوال فصل الصيف.'),
  'guigang/uprising': ('انتفاضة جينتيان', 'شهدت هذه الأراضي انطلاق الشرارة الأولى لانتفاضة تايبينغ التي هزت أركان التاريخ الصيني.'),
  'guigang/nanshan': ('معبد نانشان', 'يتميز هذا المعبد الكهفي الذي يعود لألف عام بنقوشه الصخرية وزخارفه التي تحمل كتابات إمبراطورية.'),
  'guigang/sugarcane': ('قصب السكر', 'تُعد سهول النهر الخصبة في المدينة المصدر الرئيسي لأكبر إنتاج للسكر في الصين.'),
  'yulin/medicine': ('سوق الأعشاب الطبية', 'يجمع أكبر سوق للطب التقليدي في جنوب الصين آلاف الأنواع من الأعشاب العلاجية.'),
  'yulin/goldenpalace': ('قصر يونتيان', 'يُبهر هذا القصر الثقافي الضخم المكسو بالذهب الزوار بتماثيله وقاعاته المهيبة.'),
  'yulin/lychee': ('بساتين الليتشي', 'تعتبر ثمار الليتشي الحلوة التي تُزرع على التلال الدافئة كنز الصيف الأحمر في الأسواق المحلية.'),
  'yulin/beef': ('لحم بقري يولين', 'يُعد لحم البقر المتبل بالتوابل والمعروف باسم "نيوبا" الوجبة الخفيفة المميزة للمنطقة منذ القدم.'),
  'baise/redbase': ('انتفاضة بايسه', 'تُعد الانتفاضة التي قادها دينغ شياو بينغ في شبابه نقطة تحول رئيسية في التاريخ الثوري الصيني.'),
  'baise/sinkhole': ('خسوفات ليي', 'تضم هذه المنطقة أكبر تجمع في العالم للخسوفات الأرضية العملاقة التي تخفي غابات كثيفة في أعماقها.'),
  'baise/mango': ('عاصمة المانجو', 'بفضل وديانها الحارة، تحتضن مدينة بايسه أكبر بساتين المانجو في الصين.'),
  'baise/aluminum': ('مدينة الألمنيوم', 'تُعتبر المدينة القاعدة الجنوبية لصناعة الألمنيوم في الصين نظراً لغناها بخامات البوكسيت.'),
  'hechi/longevity': ('باما موطن المعمرين', 'تشتهر منطقة باما عالمياً بأنها موطن المعمرين، حيث يتجاوز عمر العديد من سكانها المئة عام.'),
  'hechi/folksong': ('ليو سانجي', 'تستمر أسطورة "جنية الغناء" ليو سانجي حيةً من خلال مسابقات الغناء التبادلي التقليدية.'),
  'hechi/bronzedrum': ('الطبول البرونزية', 'تُعد هذه المنطقة الموطن الأكثر كثافة للطبول البرونزية المقدسة لدى قومية تشوانغ وشعوب الجبال.'),
  'hechi/geopark': ('حديقة كارست الجيولوجية', 'تعتبر هذه المنطقة عجيبة طبيعية من تضاريس الكارست، حيث تكثر فيها الحفر الانهدامية والكهوف والأنهار الجوفية.'),
  'laibin/sugarcity': ('عاصمة السكر', 'تُلقب مدينة لايبين بـ "عاصمة السكر في الصين" بفضل حقول قصب السكر الممتدة فيها.'),
  'laibin/yao': ('شعب ياو في دياو', 'يُعد شعب الياو في جبال دياو بمدينة جينشيو، بفروعهم الخمسة المتميزة، كنزاً ثقافياً فريداً.'),
  'laibin/hongshui': ('نهر هونغشوي', 'يغذي نهر هونغشوي العظيم المنطقة بسدود الطاقة والمناظر الطبيعية الخلابة التي نحتتها مياهه في الوديان.'),
  'laibin/shengtang': ('جبل شينغتانغ', 'يُعد جبل شينغتانغ أعلى قمة في سلسلة جبال دياو، ويتميز ببحار السحب والشلالات المتدفقة.'),
  'chongzuo/waterfall': ('شلالات ديتيان', 'تقع شلالات ديتيان على الحدود مع فيتنام، وتُعد أكبر شلالات عابرة للحدود في قارة آسيا.'),
  'chongzuo/langur': ('اللانغور أبيض الرأس', 'يعيش قرد اللانغور أبيض الرأس النادر حصرياً في هذه التلال الكلسية، ويُصنف ضمن أكثر أنواع القرود المهددة بالانقراض في العالم.'),
  'chongzuo/rockart': ('رسوم هواشان الصخرية', 'تضم هذه المنطقة رسومات لشخصيات حمراء نُقشت على منحدرات نهر زووجيانغ قبل ألفي عام، وهي مدرجة ضمن قائمة التراث العالمي لليونسكو.'),
  'chongzuo/borderpass': ('بوابة الصداقة', 'تُعد هذه البوابة الحدودية التاريخية مع فيتنام المنفذ البري لطريق الحرير الجنوبي.'),
  'beijing/great-wall': ('سور الصين العظيم', 'يُعد أطول تحصين في العالم، حيث يمتد لأكثر من 20 ألف كيلومتر، وتعتبر منطقة بادالينغ بالقرب من بكين أكثر أجزائه زيارةً بفضل درجاتها الحجرية وأبراج مراقبتها.'),
  'beijing/temple': ('معبد السماء', 'مجمع مقدس كان أباطرة أسرتي مينغ وتشينغ يصلون فيه سنوياً طلباً لحصاد وفير، ويشتهر بسقفه الدائري الأزرق المكون من ثلاث طبقات والذي بُني دون استخدام مسمار واحد.'),
  'beijing/pagoda': ('معبد تياننينغ', 'معبد من الطوب يعود لأسرة لياو، يبلغ ارتفاعه 57 متراً ويتكون من 13 طابقاً، ويُعد شاهداً على تاريخ بكين العريق الذي يمتد لألف عام.'),
  'beijing/opera': ('أوبرا بكين', 'فن مسرحي صيني تقليدي يجمع بين الغناء والحوار والفنون القتالية والألعاب البهلوانية، حيث تكشف أقنعة الممثلين الملونة عن طبيعة الشخصيات، فاللون الأحمر يرمز للولاء والأبيض للمكر.'),
  'zunyi/huiyi': ('مؤتمر تسونيي', 'يُعد المنزل الذي شهد اجتماع عام 1935 نقطة تحول تاريخية في مسار الثورة الصينية.'),
  'zunyi/moutai': ('بلدة ماوتاي', 'تُنتج بلدة ماوتاي الواقعة على ضفاف نهر تشيشوي مشروب الماوتائي الأسطوري الذي يُعتبر المشروب الوطني للصين.'),
  'zunyi/loushan': ('ممر لوشان', 'يُعتبر هذا الممر الجبلي المنحدر مسرحاً لمعركة تاريخية خلدتها قصيدة ماو تسي تونغ الشهيرة.'),
  'zunyi/chishui': ('شلالات تشيشوي', 'تتدفق الشلالات من منحدرات دانكسيا الحمراء وسط غابات الخيزران لتملأ وادي النهر الأحمر.'),
  'liupanshui/coolcity': ('مدينة ليوبانشوي الباردة', 'تُلقب ليوبانشوي بـ "عاصمة الصين الباردة" نظراً لأن درجات الحرارة فيها نادراً ما تتجاوز 19 درجة مئوية خلال فصل الصيف.'),
  'liupanshui/coal': ('بحر الفحم في الجنوب الغربي', 'تجعل طبقات الفحم الغنية المدينة بمثابة القلب النابض للطاقة في جنوب غرب الصين.'),
  'liupanshui/grassland': ('مراعي وومينغ', 'تنتشر قطعان الخيول وتوربينات الرياح في المروج المرتفعة التي لا نهاية لها على هضبة وومينغ.'),
  'liupanshui/kiwi': ('فاكهة الكيوي حمراء القلب', 'تُعد فاكهة الكيوي حمراء القلب التي تُزرع في المرتفعات الباردة كنزاً أخضر حلو المذاق تشتهر به المدينة.'),
  'anshun/huangguoshu': ('شلال هوانغغوشو', 'يُعد هذا الشلال الأكبر في آسيا، حيث يندفع من ارتفاع 77 متراً ليصنع رذاذه أقواس قزح ساحرة.'),
  'anshun/dixi': ('أوبرا ديكسي', 'تُؤدى أوبرا ديكسي في ساحات القرى باستخدام أقنعة خشبية للمحاربين، وتُعتبر "أحفورة حية" للأوبرا الصينية.'),
  'anshun/batik': ('فن الباتيك', 'يُعد فن الرسم بالشمع والصباغة باللون النيلي الذي تتقنه نساء قوميتي بويي ومياو الحرفة المميزة لمدينة أنشون.'),
  'anshun/tunpu': ('قرى تونبو', 'لا يزال سكان قرى الحامية الحجرية التي تعود لعهد أسرة مينغ يحافظون على أزيائهم ولهجتهم التي مر عليها 600 عام.'),
  'bijie/azalea': ('حزام أزهار الأزالية', 'يُشكل بحر أزهار الأزالية الذي يغطي التلال كل ربيع أكبر حديقة زهور طبيعية في العالم.'),
  'bijie/zhijin': ('كهف تشيجين', 'يُعد كهف تشيجين بفضل غابات الصواعد العملاقة فيه "قصراً تحت الأرض" وأكثر الكهوف روعة في الصين.'),
  'bijie/caohai': ('كركي بحيرة كاوهاي', 'تُصبح البحيرة الضحلة في منطقة وينينغ موطناً شتوياً لطيور الكركي سوداء العنق النادرة.'),
  'bijie/potato': ('عاصمة البطاطس', 'تُعد مدينة بيجي مخزن البطاطس في الصين بفضل محاصيل المرتفعات، وتشتهر بطاطس منطقة ويرينغ في جميع أنحاء البلاد.'),
  'qujing/rapeseed': ('بحر الكانولا في لوي بينغ', 'تجذب حقول الكانولا الذهبية في لوي بينغ مربي النحل والمصورين في كل شهر فبراير.'),
  'qujing/ham': ('لحم شوانوي المقدد', 'يُعد لحم شوانوي المقدد، الذي يُعالج بالملح منذ قرون، فخر المائدة في مقاطعة يونان.'),
  'qujing/jiulong': ('شلالات جيولونغ', 'تشكل الشلالات العشر المتدرجة لنهر التنانين التسعة أجمل سلسلة شلالات في الصين.'),
  'qujing/sandforest': ('غابة الرمال الملونة', 'تشكل الأعمدة الرملية الملونة التي نحتتها الرياح حديقة منحوتات طبيعية في منطقة لوليانغ.'),
  'yuxi/fuxian': ('بحيرة فوكسيان', 'تعتبر ثاني أعمق بحيرة في الصين، وهي مرآة جبلية ذات مياه صافية كالكريستال.'),
  'yuxi/nieer': ('الموسيقار ني إر', 'تُكرم مدينة يوشي ابنها الموسيقار ني إر، ملحن النشيد الوطني، بحديقة موسيقية ونصب تذكاري.'),
  'yuxi/chengjiang': ('أحافير تشنغجيانغ', 'تُعد طبقات الأحافير التي يعود تاريخها إلى 530 مليون سنة موقعاً تراثياً لليونسكو يوثق فجر الحياة الحيوانية.'),
  'yuxi/kiln': ('أفران يوشي', 'يُعد الفرن القديم الذي يعود إلى عصر أسرة يوان مهد صناعة الخزف الأزرق والأبيض في يونان.'),
  'dali/threepagodas': ('البوغودات الثلاث', 'تقف البوغودات الثلاث الرشيقة عند سفح جبال تسانغشان منذ ألف عام، وتعتبر رمزاً لمملكة دالي القديمة.'),
  'dali/erhai': ('بحيرة إرهاي', 'تبدو بحيرة إرهاي الجبلية التي تتخذ شكل الأذن كلوحة فنية تزينها قوارب الصيد والقرى المطلة على ضفافها.'),
  'dali/cangshan': ('جبال تسانغشان', 'ترتفع جبال تسانغشان بقممها التسع عشرة المغطاة بالثلوج كستار أخضر خلف مدينة دالي.'),
  'dali/wind': ('الريح والزهر والثلج والقمر', 'تُشبه جماليات دالي الأربع، المتمثلة في رياح شياغوان وزهور شانغغوان وثلوج تسانغشان وقمر إرهاي، قصيدة شعرية.'),
  'lijiang/oldtown': ('مدينة ليجيانغ القديمة', 'تُعد هذه المدينة المدرجة ضمن قائمة اليونسكو، بقنواتها المائية ومنازلها الخشبية ذات الأسطح القرميدية، القلب النابض لثقافة الناشي.'),
  'lijiang/snowmountain': ('جبل تنين اليشم الثلجي', 'تتألق القمة الجليدية التي يبلغ ارتفاعها 5596 متراً فوق المدينة كأنها تنين يشم نائم.'),
  'lijiang/dongba': ('كتابة الدونغبا', 'تُعد كتابة الدونغبا التصويرية الخاصة بكهنة الناشي آخر نظام كتابة تصويري لا يزال مستخدماً في العالم.'),
  'lijiang/tigerleaping': ('مضيق قفزة النمر', 'يُعتبر هذا المضيق، الذي يُقال إن نمراً عبره بقفزة واحدة، من بين أعمق الأخاديد على وجه الأرض.'),
  'lincang/dianhong': ('شاي ديانهونغ الأسود', 'ساهم شاي ديانهونغ الأسود ذو البراعم الذهبية، الذي يشتهر به إقليم فنغتشينغ، في إيصال اسم مقاطعة يونان إلى العالم.'),
  'lincang/wadrum': ('طبول شعب الوا الخشبية', 'تتردد أصداء الطبول الخشبية المقدسة لشعب الوا في القرى الجبلية أثناء رقصة الطبول الشهيرة.'),
  'lincang/teatrees': ('أشجار الشاي القديمة', 'تعد لينتسانغ موطناً لأشجار الشاي البرية التي يعود عمرها لآلاف السنين، وهي تحرس الغابات التي نشأ فيها الشاي.'),
  'lincang/lancang': ('نهر لانسانغ', 'يتدفق نهر لانسانغ، وهو المجرى العلوي لنهر ميكونغ، نحو الجنوب ليضيء الوديان بسدود مياهه العملاقة.'),
  'puer/tea': ('شاي بوير', 'يُعد شاي بوير المضغوط، الذي يزداد جودةً مع مرور الزمن، كنزاً حياً يحمل اسم هذه المدينة الجبلية.'),
  'puer/coffee': ('عاصمة القهوة في الصين', 'تنمو أكثر من نصف كمية القهوة في الصين على منحدرات بوير الضبابية، حتى باتت رائحة القهوة تعبق في أرجاء المدينة.'),
  'puer/teahorse': ('طريق الشاي والخيول', 'بدأ طريق الشاي والخيول القديم، الذي كانت تسلكه قوافل البغال لنقل الشاي إلى التبت، من مدينة بوير متسلقاً نحو السحاب.'),
  'puer/peafowl': ('الطاووس الأخضر', 'تعتبر الغابات الاستوائية التي تأوي طيور الطاووس الأخضر النادرة بمثابة التاج البري لهذه المدينة.'),
  'baoshan/volcano': ('براكين تينغتشونغ', 'تحول سبعة وتسعون مخروطاً بركانياً خامداً سهول تينغتشونغ إلى مشهد طبيعي يشبه سطح القمر.'),
  'baoshan/rehai': ('بحر ريهاي الساخن', 'تتصاعد الأبخرة من الينابيع الحارة في وادي ريهاي، حيث تُطهى البيض في مياه الينابيع المغلية.'),
  'baoshan/heshun': ('بلدة هيشون', 'تحتفظ بلدة هيشون، وهي بلدة التجار الذين سافروا إلى الخارج، بأقدم مكتبة قروية في الصين.'),
  'baoshan/gaoligong': ('جبال غاوليغونغ', 'تُعد جبال غاوليغونغ، بما تضمه من وديان الفراشات والغابات الدافئة، كنزاً حقيقياً للتنوع البيولوجي.'),
  'deyang/sanxingdui': ('أطلال سانشينغدوي', 'كشفت الأقنعة البرونزية العملاقة ذات العيون الجاحظة عن حضارة شو الغامضة التي يعود تاريخها إلى ثلاثة آلاف عام.'),
  'deyang/jiannanchun': ('نبيذ جيانان تشون', 'يُعد نبيذ جيانان تشون، الذي كان يُقدم في بلاط أسرة تانغ، مشروباً مقطراً يعود تاريخه إلى خمسة عشر قرناً.'),
  'deyang/nianhua': ('مطبوعات ميانجو للعام الجديد', 'تُعلق هذه اللوحات الخشبية المرسومة يدوياً على المداخل لجلب الحظ السعيد وإضفاء لمسة من البهجة.'),
  'deyang/turbine': ('عاصمة الصناعات الثقيلة', 'تُصنع معظم التوربينات والمولدات الضخمة في البلاد داخل ورش مدينة دييانغ.'),
  'mianyang/libai': ('مسقط رأس لي باي', 'نشأ الشاعر الخالد لي باي بين جبال جيانغيو، ولا تزال أصداء قصائده تتردد في أرجائها حتى اليوم.'),
  'mianyang/sciencecity': ('مدينة العلوم', 'تُعد ميانيانغ المدينة الوحيدة في الصين التي تحمل لقب مدينة العلوم والتكنولوجيا، حيث تُبنى ملامح المستقبل في مختبراتها.'),
  'mianyang/qiang': ('أبراج تشيانغ الحجرية', 'تقف أبراج المراقبة الحجرية الخاصة بشعب تشيانغ شامخة في القرى الجبلية ببيتشوان منذ قرون.'),
  'mianyang/mifen': ('نودلز الأرز في ميانيانغ', 'تستيقظ المدينة كل صباح على رائحة نودلز الأرز الطازجة المطهوة في مرق الدجاج والأحشاء.'),
  'nanchong/langzhong': ('مدينة لانغتشونغ القديمة', 'تستقر هذه المدينة القديمة، التي صُممت وفق مبادئ الفنغ شوي، في أحضان منعطف نهري وتُعد الأفضل حفظاً في الصين.'),
  'nanchong/silk': ('عاصمة الحرير', 'بفضل تاريخ يمتد لألفي عام في صناعة النسيج، تُعتبر نانتشونغ عاصمة الحرير في غرب الصين.'),
  'nanchong/zhangfei': ('لحم تشانغ فاي البقري', 'يُنسب هذا اللحم البقري المملح والمتبل إلى بطل عصر الممالك الثلاث تشانغ فاي.'),
  'nanchong/zhude': ('مسقط رأس تشو دي', 'يُعد منزل المارشال تشو دي المتواضع في ييلونغ وجهة تاريخية هامة للزوار.'),
  'yibin/wuliangye': ('نبيذ ووليانغيه', 'يُصنع نبيذ ووليانغيه من تقطير خمسة أنواع من الحبوب، ويُعد من أرقى أنواع المشروبات الروحية في الصين.'),
  'yibin/firstcity': ('المدينة الأولى على نهر اليانغتسي', 'تُلقب ييبين بالمدينة الأولى لنهر اليانغتسي، حيث يلتقي فيها نهرا مين وجينشا لتشكيل مجرى النهر العظيم.'),
  'yibin/bamboosea': ('بحر الخيزران في شونان', 'يمتد بحر من الخيزران ليغطي مئة وعشرين تلة، متموجاً مع الرياح كبحر أخضر شاسع.'),
  'yibin/ranmian': ('نودلز الاحتراق', 'تُعد نودلز الاحتراق، التي تُعجن لتصبح جافة لدرجة أن زيتها قد يشتعل، النجم المتألق في وجبة الإفطار بمدينة ييبين.'),
  'luzhou/laojiao': ('أقبية لاوجياو', 'تُعد حفر التخمير الطينية التي استُخدمت باستمرار منذ عام 1573 جوهر صناعة مشروب البايجيو العطري.'),
  'luzhou/port': ('ميناء يانغتسي', 'تُعتبر هذه المدينة المينائية الواقعة عند ملتقى نهرين بوابة سيتشوان المائية نحو البحر.'),
  'luzhou/longan': ('بساتين اللونجان', 'يُزرع اللونجان، المعروف بفاكهة عين التنين ذات المذاق العسلي، على منحدرات الأنهار الدافئة.'),
  'luzhou/umbrella': ('مظلات الورق الزيتي', 'تُعد مظلات الورق الزيتي المصنوعة يدوياً على يد حرفيي فنشوي إرثاً فنياً عريقاً يعود لأربعمائة عام.'),
  'leshan/giantbuddha': ('تمثال بوذا العملاق في ليشأن', 'يطل تمثال بوذا الجالس، المنحوت في الصخر بارتفاع 71 متراً، على ملتقى النهرين منذ اثني عشر قرناً.'),
  'leshan/emei': ('جبل إيمي', 'تتألق القمة الذهبية لجبل إيمي، أحد الجبال الأربعة المقدسة في البوذية، فوق بحر من السحب.'),
  'leshan/monkeys': ('قرود المكاك في إيمي', 'تشتهر قرود المكاك المشاكسة التي تسكن مسارات الجبل بجرأتها في تفتيش حقائب الحجاج.'),
  'leshan/qiaojiao': ('حساء لحم البقر تشياوجياو', 'يُعد حساء لحم البقر المطهو بالأعشاب، المعروف بـ "تشياوجياو"، طبقاً كلاسيكياً يعود تاريخه لقرن من الزمان في شوارع ليشأن.'),
  'zigong/saltwell': ('آبار الملح العميقة', 'يُعد بئر شينهاي، وهو الأول في العالم الذي يتجاوز عمقه ألف متر، إنجازاً تاريخياً لمدينة الملح التي يعود تاريخها لألفي عام.'),
  'zigong/lantern': ('مهرجان زيغونغ للفوانيس', 'تتحول المدينة في كل عام جديد إلى عالم خيالي بفضل حدائق الفوانيس العملاقة المتوهجة.'),
  'zigong/dinosaur': ('متحف الديناصورات', 'تجعل آلاف الأحافير المستخرجة من طبقات العصر الجوراسي مدينة زيغونغ عاصمة الديناصورات في الصين.'),
  'zigong/rabbit': ('أرنب لينغتو البارد', 'يُعتبر طبق الأرنب الحار الذي يُقدم بارداً، والمعروف بـ "لينغتو"، أشهر مقبلات سيتشوان الجريئة في هذه المدينة.'),
  'panzhihua/steel': ('عاصمة الفاناديوم والتيتانيوم', 'تعمل مدينة الصلب العملاقة المبنية وسط الجبال على استخراج أغنى رواسب الفاناديوم والتيتانيوم في العالم.'),
  'panzhihua/fruitvalley': ('وادي الفاكهة المشمس', 'تنضج ثمار المانجو والرمان في هذا الوادي الجاف والحار تحت أشعة الشمس حتى في فصل الشتاء.'),
  'panzhihua/sunshine': ('مدينة شمس الشتاء', 'بفضل تمتعها بـ 2700 ساعة من ضوء الشمس سنوياً، تُعد بانزهيوا وجهة مثالية للاستجمام في شتاء معتدل.'),
  'panzhihua/jinsha': ('نهر جينشا', 'يتدفق نهر جينشا ذو الرمال الذهبية عبر المدينة، حافراً في طريقه ودياناً عميقة.'),
  'dazhou/gas': ('عاصمة الغاز الطبيعي', 'يجعل حقل بوغوانغ العملاق من مدينة داتشو قاعدة رئيسية للطاقة والغاز الطبيعي في الصين.'),
  'dazhou/ba': ('إرث مملكة با', 'تتحدث أطلال لوجيا با عن تاريخ محاربي مملكة با القدماء الذين اشتهروا بسيوفهم ذات الأوراق الصفصافية.'),
  'dazhou/dengying': ('لحم البقر بأسلوب خيال الظل', 'يُقطع لحم البقر الحار إلى شرائح رقيقة جداً تسمح بمرور الضوء من خلالها، وقد استمد هذا الطبق اسمه من عروض خيال الظل التقليدية.'),
  'dazhou/hanque': ('أبراج بوابة هان الحجرية', 'تعد أبراج "كيو" الحجرية في منطقة تشو شيان، والتي يعود تاريخها إلى ألفي عام، نموذجاً حياً على روعة العمارة في عهد أسرة هان.'),
  'guangyuan/jianmen': ('ممر جيانمن', 'يُعرف ممر جبل السيف بقدرته الدفاعية الأسطورية حيث يمكن لرجل واحد أن يصد عشرة آلاف، وهو يمثل البوابة الحصينة لطريق شو.'),
  'guangyuan/wuzetian': ('مسقط رأس الإمبراطورة وو زتيان', 'وُلدت هنا الإمبراطورة الوحيدة في تاريخ الصين، وو زتيان، ويُكرمها معبد هوانغزي منذ أكثر من ألف عام.'),
  'guangyuan/plankroad': ('الطرق الخشبية القديمة', 'تعتبر الطرق الخشبية المثبتة على المنحدرات الصخرية الشاهقة شاهداً على الجرأة البشرية في طريق شو الذي وُصف بأنه أصعب من الصعود إلى السماء.'),
  'guangyuan/cypress': ('ممر أشجار السرو في كويون', 'تحول عشرات الآلاف من أشجار السرو القديمة التي تعود إلى عصر الممالك الثلاث الطريق التاريخي إلى نفق أخضر وارف.'),
  'yaan/panda': ('مهد الباندا', 'اكتُشف الباندا العملاق علمياً لأول مرة في منطقة باوشينغ عام 1869، ولا تزال قاعدة بيفنغشيا تحافظ على هذا الإرث الطبيعي.'),
  'yaan/rain': ('مدينة المطر', 'تغسل أمطار ياآن أسطح المنازل كل ليلة تقريباً، مما يضفي على المدينة بريقاً أخضر متألقاً.'),
  'yaan/mengding': ('شاي جبل مينغدينغ', 'زُرع الشاي لأول مرة بأيدٍ بشرية على جبل مينغدينغ قبل ألفي عام، ويُعد الجبل المهد الحقيقي لثقافة الشاي.'),
  'yaan/yayu': ('سمك يا', 'يُعد سمك يا الأسطوري، الذي يعيش في الجداول المغذاة بمياه الثلوج، فخر المدينة ويُقدم في أوانٍ فخارية تغلي.'),
  'xianyang/qincapital': ('عاصمة إمبراطورية تشين', 'هنا قامت عاصمة أسرة تشين، أول من وحد الصين، ومن شيانيانغ انطلقت مسيرة بناء الإمبراطورية.'),
  'xianyang/qianling': ('ضريح تشيانلينغ', 'يتحدى الضريح الجبلي الذي يضم رفات الإمبراطورة وو زتيان وزوجها التاريخ بوجود لوحته الحجرية الفارغة.'),
  'xianyang/zhengguo': ('قناة تشنغقو', 'حوّلت هذه القناة المائية التي يعود تاريخها إلى ألفي عام سهول غوانتشونغ إلى مخزن للحبوب في عهد أسرة تشين.'),
  'xianyang/guokui': ('خبز غوكوي', 'يُعد خبز غوكوي المقرمش، الذي يضاهي حجمه غطاء القدر، وجبة خفيفة تقليدية توارثتها موائد مقاطعة شنشي لقرون.'),
  'baoji/bronze': ('عاصمة الأواني البرونزية', 'احتضنت مدينة باوجي آلاف القطع البرونزية من عهد أسرة تشو، بما في ذلك إناء "خه تسون" الذي يحمل أول نقش معروف لاسم الصين.'),
  'baoji/famen': ('معبد فامن', 'كان معبد فامن بمثابة الخزانة المقدسة لأباطرة أسرة تانغ، حيث يحرس رفات إصبع بوذا.'),
  'baoji/taibai': ('جبل تايباي', 'يُعتبر جبل تايباي، الذي يرتفع 3771 متراً فوق سلسلة جبال تشينلينغ، قمة أسطورية تكتسي بالثلوج حتى في فصل الصيف.'),
  'baoji/saozi': ('نودلز ساو زي', 'تجسد نودلز ساو زي من منطقة تشيشان، بصلصتها الحامضة والحارة، المذاق الحي لتقاليد الطهي التي تعود إلى ثلاثة آلاف عام من عهد أسرة تشو.'),
};
